export const QUESTION_BANK = [
  // ---------- Penalaran Umum (PU) ----------
  { id: "pu1", subtes: "PU", topic: "Silogisme", q: "Semua peserta yang lulus seleksi administrasi mengikuti tes wawancara. Andi adalah peserta yang lulus seleksi administrasi. Kesimpulan yang tepat:", opts: ["Andi mengikuti tes wawancara", "Andi tidak mengikuti tes wawancara", "Andi mungkin mengikuti tes wawancara", "Tidak bisa disimpulkan"], answer: 0, pembahasan: "Berlaku modus ponens: semua yang lolos seleksi administrasi mengikuti wawancara, dan Andi termasuk yang lolos, jadi Andi pasti mengikuti wawancara.", paket: 1 },
  { id: "pu2", subtes: "PU", topic: "Silogisme", q: "Jika semua yang lulus UTBK rajin belajar, dan Rani rajin belajar, maka…", opts: ["Rani pasti lulus UTBK", "Rani belum tentu lulus UTBK", "Rani tidak lulus UTBK", "Rani bukan peserta UTBK"], answer: 1, pembahasan: "Pernyataan hanya menyatakan 'lulus UTBK → rajin belajar', bukan sebaliknya. Rajin belajar tidak otomatis menjamin lulus UTBK.", paket: 1 },
  { id: "pu3", subtes: "PU", topic: "Deret", q: "Manakah pola yang melanjutkan deret: 2, 6, 12, 20, 30, ...?", opts: ["36", "40", "42", "44"], answer: 2, pembahasan: "Selisih antarsuku bertambah 2 setiap langkah (4,6,8,10). Suku berikutnya: 30 + 12 = 42.", paket: 1 },
  { id: "pu4", subtes: "PU", topic: "Silogisme", q: "Setiap peserta yang lolos tes kesehatan boleh mengikuti pelatihan. Peserta bernama Rudi belum lolos tes kesehatan. Maka…", opts: ["Rudi pasti sudah mengikuti pelatihan", "Rudi belum boleh mengikuti pelatihan", "Pelatihan itu batal total", "Tidak ada hubungan sama sekali"], answer: 1, pembahasan: "Syarat lolos tes kesehatan belum terpenuhi, sehingga konsekuensinya (boleh ikut pelatihan) juga belum berlaku.", paket: 1 },
  { id: "pu5", subtes: "PU", topic: "Analogi", q: "JANTUNG : TUBUH = ... : ...", opts: ["Mesin : Pabrik", "Daun : Ranting", "Atap : Rumah", "Batu : Pasir"], answer: 0, pembahasan: "Jantung adalah 'penggerak utama' tubuh, sama seperti mesin yang menjadi 'penggerak utama' pabrik.", paket: 1 },
  { id: "pu6", subtes: "PU", topic: "Deret", q: "Lanjutkan deret huruf: A, C, F, J, O, ...", opts: ["S", "T", "U", "R"], answer: 2, pembahasan: "Loncatan antarhuruf bertambah 1 setiap langkah: A(+2)C(+3)F(+4)J(+5)O(+6)U.", paket: 1 },
  { id: "pu7", subtes: "PU", topic: "Penalaran Sebab-Akibat", q: "Jika curah hujan tinggi maka risiko longsor di lereng meningkat. Di Desa Argosari risiko longsor tidak meningkat pekan ini. Kesimpulan yang paling tepat:", opts: ["Curah hujan pekan ini pasti tinggi", "Curah hujan pekan ini tidak tinggi", "Curah hujan tidak berpengaruh pada longsor", "Tidak dapat disimpulkan sama sekali"], answer: 1, pembahasan: "Modus tollens: akibat (longsor meningkat) tidak terjadi, maka sebabnya (curah hujan tinggi) juga tidak terjadi.", paket: 1 },
  { id: "pu8", subtes: "PU", topic: "Silogisme", q: "Sebagian mahasiswa ikut klub robotika. Semua anggota klub robotika pandai coding. Maka…", opts: ["Semua mahasiswa pandai coding", "Sebagian mahasiswa pandai coding", "Tidak ada mahasiswa yang pandai coding", "Semua yang pandai coding adalah mahasiswa"], answer: 1, pembahasan: "Subset mahasiswa yang ikut klub robotika sudah pasti pandai coding, sehingga minimal 'sebagian' mahasiswa pandai coding — bukan berarti semuanya.", paket: 1 },
  { id: "pu9", subtes: "PU", topic: "Logika Pernyataan", q: "\"Jika hujan turun, maka acara di lapangan dibatalkan.\" Pernyataan ini senilai (ekuivalen) dengan…", opts: ["Jika acara tidak dibatalkan, hujan tidak turun", "Jika hujan tidak turun, acara dibatalkan", "Acara dibatalkan hanya jika hujan tidak turun", "Hujan turun hanya jika acara dibatalkan"], answer: 0, pembahasan: "Pernyataan 'jika P maka Q' ekuivalen secara logis dengan kontraposisinya 'jika bukan Q maka bukan P'.", paket: 1 },
  { id: "pu10", subtes: "PU", topic: "Deret", q: "Lanjutkan deret: 3, 4, 7, 11, 18, ...", opts: ["25", "27", "29", "31"], answer: 2, pembahasan: "Pola Fibonacci-like: tiap suku adalah jumlah dua suku sebelumnya. 7+11=18, 11+18=29.", paket: 1 },
  { id: "pu11", subtes: "PU", topic: "Penalaran Posisi", q: "Dalam antrean pengambilan hasil tes, Budi berada tepat di depan Citra dan tepat di belakang Dina. Jika Dina berada di posisi ke-3, maka Citra berada di posisi ke-…", opts: ["2", "4", "5", "3"], answer: 2, pembahasan: "Urutan tetapnya: Dina - Budi - Citra. Dina di posisi 3, Budi di posisi 4, Citra di posisi 5.", paket: 1 },
  { id: "pu12", subtes: "PU", topic: "Analogi", q: "PENULIS : BUKU = ... : ...", opts: ["Pelukis : Lukisan", "Sopir : Jalan", "Guru : Sekolah", "Petani : Sawah"], answer: 0, pembahasan: "Penulis menghasilkan karya berupa buku, sama seperti pelukis menghasilkan karya berupa lukisan.", paket: 1 },
  { id: "pu13", subtes: "PU", topic: "Silogisme", q: "Tidak ada produk yang lolos uji mutu dijual tanpa label SNI. Produk ini dijual tanpa label SNI. Maka produk ini…", opts: ["Pasti lolos uji mutu", "Pasti tidak lolos uji mutu", "Tidak bisa dipastikan lolos uji mutu", "Tidak relevan dengan uji mutu"], answer: 1, pembahasan: "Premis berarti tidak ada material yang lolos mutu sekaligus dipakai tanpa sertifikat. Karena besi ini dipakai tanpa sertifikat, ia pasti tidak lolos uji mutu (modus tollens).", paket: 1 },
  { id: "pu14", subtes: "PU", topic: "Deret", q: "Lanjutkan deret: 1, 1, 2, 3, 5, 8, 13, ...", opts: ["18", "20", "21", "24"], answer: 2, pembahasan: "Deret Fibonacci: tiap suku adalah jumlah dua suku sebelumnya. 8+13=21.", paket: 1 },
  { id: "pu15", subtes: "PU", topic: "Penalaran Sebab-Akibat", q: "Semakin berat suatu benda, semakin besar gaya yang dibutuhkan untuk mengangkatnya. Benda A lebih berat dari benda B. Maka…", opts: ["Gaya untuk mengangkat benda A lebih besar dari benda B", "Gaya untuk mengangkat benda A lebih kecil dari benda B", "Gaya untuk mengangkat keduanya pasti sama", "Berat tidak memengaruhi gaya angkat"], answer: 0, pembahasan: "Berat lebih besar (benda A) membutuhkan gaya angkat yang lebih besar pula — hubungan berbanding lurus.", paket: 1 },
  { id: "pu16", subtes: "PU", topic: "Diagram Venn", q: "Semua peserta yang lolos tes potensi akademik (TPA) mengikuti tes wawancara. Sebagian peserta tes wawancara juga mengikuti tes praktik lapangan. Berdasarkan pernyataan tersebut, yang pasti benar adalah…", opts: ["Semua peserta TPA mengikuti tes praktik lapangan", "Sebagian peserta TPA mungkin mengikuti tes praktik lapangan", "Tidak ada peserta TPA yang ikut tes praktik lapangan", "Semua peserta tes praktik lapangan lolos TPA"], answer: 1, pembahasan: "Karena hanya 'sebagian' peserta wawancara yang ikut praktik lapangan, tidak bisa dipastikan berapa banyak dari peserta TPA yang termasuk golongan itu — hanya bisa dikatakan 'mungkin sebagian'.", paket: 1 },
  { id: "pu17", subtes: "PU", topic: "Deret", q: "Lanjutkan deret: 5, 10, 20, 35, 55, ...?", opts: ["75", "80", "85", "90"], answer: 1, pembahasan: "Selisih antarsuku bertambah 5 setiap langkah (5,10,15,20). Suku berikutnya: 55+25=80.", paket: 1 },
  { id: "pu18", subtes: "PU", topic: "Analogi", q: "PALU : PAKU = ... : ...", opts: ["Obeng : Sekrup", "Gergaji : Kayu", "Cat : Kuas", "Meteran : Jarak"], answer: 0, pembahasan: "Palu berfungsi memasang paku, sama seperti obeng berfungsi memasang sekrup — hubungan alat dan objek yang dipasangnya.", paket: 1 },
  { id: "pu19", subtes: "PU", topic: "Silogisme", q: "Semua kendaraan yang belum lolos uji emisi dilarang beroperasi di jalan raya. Mobil bernomor B10 beroperasi di jalan raya. Maka…", opts: ["Mobil itu pasti belum lolos uji emisi", "Mobil itu pasti sudah lolos uji emisi", "Mobil itu tidak beroperasi", "Tidak ada hubungan antara operasi dan uji emisi"], answer: 1, pembahasan: "Karena mobil itu beroperasi (berarti tidak dilarang), dan yang dilarang hanya yang belum lolos emisi, maka mobil ini pasti sudah lolos uji emisi (kontraposisi).", paket: 1 },
  { id: "pu20", subtes: "PU", topic: "Penalaran Posisi", q: "Lima berkas disusun berdasarkan tanggal masuk: Berkas P lebih baru dari Q, Q lebih baru dari R, R lebih baru dari S, dan S lebih baru dari T. Berkas manakah yang paling lama?", opts: ["P", "Q", "S", "T"], answer: 3, pembahasan: "Urutan dari terbaru ke terlama: P, Q, R, S, T. Berkas T adalah yang terlama.", paket: 1 },
  { id: "pu21", subtes: "PU", topic: "Deret", q: "Lanjutkan deret: 81, 27, 9, 3, ...?", opts: ["1", "0", "2", "1/3"], answer: 0, pembahasan: "Setiap suku dibagi 3 dari suku sebelumnya (81, 27, 9, 3). Suku berikutnya: 3 ÷ 3 = 1.", paket: 1 },
  { id: "pu22", subtes: "PU", topic: "Logika Pernyataan", q: "\"Jika kualitas bahan baku di bawah standar, maka produksi dihentikan.\" Ingkaran (negasi) yang tepat dari pernyataan tersebut adalah…", opts: ["Kualitas bahan baku di bawah standar dan produksi tidak dihentikan", "Kualitas bahan baku di atas standar dan produksi dihentikan", "Jika produksi dihentikan, kualitas bahan baku di bawah standar", "Kualitas bahan baku di bawah standar atau produksi dihentikan"], answer: 0, pembahasan: "Ingkaran dari 'jika P maka Q' adalah 'P dan bukan Q' — kualitas di bawah standar TAPI produksi tidak dihentikan.", paket: 1 },
  { id: "pu23", subtes: "PU", topic: "Penalaran Sebab-Akibat", q: "Semakin lama seseorang berlatih, semakin tinggi keterampilannya. Andi berlatih lebih lama dari Budi pada bidang yang sama. Maka…", opts: ["Keterampilan Andi lebih tinggi dari Budi", "Keterampilan Andi lebih rendah dari Budi", "Keterampilan keduanya pasti sama", "Lama berlatih tidak memengaruhi keterampilan"], answer: 0, pembahasan: "Semakin lama berlatih, semakin tinggi keterampilan — hubungan berbanding lurus, jadi Andi (berlatih lebih lama) keterampilannya lebih tinggi.", paket: 1 },
  { id: "pu24", subtes: "PU", topic: "Analogi", q: "PENYAKIT : OBAT = ... : ...", opts: ["Kebakaran : Alat pemadam", "Hujan : Payung", "Gelap : Lampu", "Panas : Kipas"], answer: 0, pembahasan: "Obat menjadi penanggulangan untuk penyakit, sama seperti alat pemadam menjadi penanggulangan untuk kebakaran.", paket: 1 },
  { id: "pu25", subtes: "PU", topic: "Deret", q: "Lanjutkan deret: 2, 3, 5, 8, 13, 21, ...?", opts: ["30", "32", "34", "36"], answer: 2, pembahasan: "Pola Fibonacci: tiap suku adalah jumlah dua suku sebelumnya. 13+21=34.", paket: 1 },
  { id: "pu26", subtes: "PU", topic: "Silogisme", q: "Semua anggota tim yang lolos seleksi wawancara mendapatkan pelatihan lanjutan. Rani belum mendapatkan pelatihan lanjutan. Maka…", opts: ["Rani pasti lolos seleksi wawancara", "Rani pasti tidak lolos seleksi wawancara", "Tidak bisa dipastikan status seleksi Rani", "Pelatihan lanjutan tidak berkaitan dengan seleksi"], answer: 1, pembahasan: "Berlaku modus tollens: karena Rani tidak mendapat pelatihan lanjutan (akibat tidak terjadi), maka ia pasti tidak lolos wawancara (sebab juga tidak terjadi).", paket: 1 },
  { id: "pu27", subtes: "PU", topic: "Deret", q: "Lanjutkan deret: 4, 9, 16, 25, 36, ...?", opts: ["42", "45", "47", "49"], answer: 3, pembahasan: "Polanya adalah kuadrat bilangan berurutan: 2²,3²,4²,5²,6²,7² = 4,9,16,25,36,49.", paket: 1 },
  { id: "pu28", subtes: "PU", topic: "Analogi", q: "DOKTER : PASIEN = ... : ...", opts: ["Guru : Murid", "Buku : Rak", "Mobil : Jalan", "Baju : Lemari"], answer: 0, pembahasan: "Dokter memberikan layanan medis kepada pasien, sama seperti guru memberikan pengajaran kepada murid — hubungan pemberi dan penerima layanan.", paket: 1 },
  { id: "pu29", subtes: "PU", topic: "Penalaran Posisi", q: "Empat rumah P, Q, R, S berjejer dalam satu baris dari kiri ke kanan. Rumah P tepat di sebelah kiri rumah Q. Rumah R tepat di sebelah kiri rumah S. Rumah Q berada di sebelah kiri rumah R. Urutan rumah dari kiri ke kanan adalah…", opts: ["P, Q, R, S", "Q, P, S, R", "P, R, Q, S", "R, S, P, Q"], answer: 0, pembahasan: "P harus tepat di kiri Q (blok PQ), dan R tepat di kiri S (blok RS). Karena Q di sebelah kiri R, blok PQ mendahului blok RS, sehingga urutannya P, Q, R, S.", paket: 1 },
  { id: "pu30", subtes: "PU", topic: "Logika Pernyataan", q: "\"Jika laporan keuangan diaudit, maka investor mendapat kepastian informasi.\" Kontraposisi yang tepat dari pernyataan tersebut adalah…", opts: ["Jika investor tidak mendapat kepastian informasi, laporan keuangan tidak diaudit", "Jika laporan keuangan tidak diaudit, investor tidak mendapat kepastian informasi", "Jika investor mendapat kepastian informasi, laporan keuangan diaudit", "Laporan keuangan diaudit hanya jika investor tidak mendapat kepastian informasi"], answer: 0, pembahasan: "Kontraposisi dari 'jika P maka Q' adalah 'jika bukan Q maka bukan P'.", paket: 1 },
  { id: "pu31", subtes: "PU", topic: "Silogisme", q: "Semua penari yang lolos audisi tampil di pertunjukan utama. Sari tidak tampil di pertunjukan utama. Maka…", opts: ["Sari pasti lolos audisi", "Sari pasti tidak lolos audisi", "Status audisi Sari tidak bisa dipastikan", "Pertunjukan utama tidak berkaitan dengan audisi"], answer: 1, pembahasan: "Modus tollens: karena Sari tidak tampil di pertunjukan utama (akibat tidak terjadi), maka ia pasti tidak lolos audisi (sebab juga tidak terjadi).", paket: 2 },
  { id: "pu32", subtes: "PU", topic: "Deret", q: "Lanjutkan deret: 1, 4, 9, 16, 25, ...?", opts: ["30", "32", "34", "36"], answer: 3, pembahasan: "Polanya kuadrat bilangan asli berurutan: 1²,2²,3²,4²,5²,6² = 1,4,9,16,25,36.", paket: 2 },
  { id: "pu33", subtes: "PU", topic: "Analogi", q: "NELAYAN : IKAN = ... : ...", opts: ["Petani : Padi", "Sopir : Mobil", "Dokter : Rumah Sakit", "Guru : Papan Tulis"], answer: 0, pembahasan: "Nelayan menangkap/memperoleh ikan sebagai hasil pekerjaannya, sama seperti petani memperoleh padi dari hasil bertani.", paket: 2 },
  { id: "pu34", subtes: "PU", topic: "Penalaran Posisi", q: "Lima pelari finish berurutan. Ani finish sebelum Budi. Citra finish setelah Budi. Dedi finish sebelum Ani. Eka finish paling akhir. Urutan yang mungkin dari finish pertama adalah…", opts: ["Dedi, Ani, Budi, Citra, Eka", "Ani, Dedi, Budi, Citra, Eka", "Dedi, Ani, Citra, Budi, Eka", "Budi, Ani, Dedi, Citra, Eka"], answer: 0, pembahasan: "Urutan syaratnya: Dedi sebelum Ani, Ani sebelum Budi, Budi sebelum Citra, dan Eka paling akhir — hanya urutan Dedi, Ani, Budi, Citra, Eka yang memenuhi semua syarat.", paket: 2 },
  { id: "pu35", subtes: "PU", topic: "Logika Pernyataan", q: "\"Jika stok bahan baku habis, maka produksi dihentikan.\" Manakah pernyataan yang merupakan invers dari pernyataan tersebut?", opts: ["Jika produksi dihentikan, maka stok bahan baku habis", "Jika stok bahan baku tidak habis, maka produksi tidak dihentikan", "Jika produksi tidak dihentikan, maka stok bahan baku tidak habis", "Stok bahan baku habis dan produksi tidak dihentikan"], answer: 1, pembahasan: "Invers dari 'jika P maka Q' adalah 'jika bukan P maka bukan Q'.", paket: 2 },
  { id: "pu36", subtes: "PU", topic: "Penalaran Sebab-Akibat", q: "Semakin tinggi tingkat kelembapan udara, semakin lambat proses pengeringan pakaian. Hari ini kelembapan udara lebih tinggi dari kemarin. Maka…", opts: ["Pakaian hari ini kering lebih cepat dari kemarin", "Pakaian hari ini kering lebih lambat dari kemarin", "Kecepatan pengeringan hari ini dan kemarin pasti sama", "Kelembapan tidak memengaruhi pengeringan"], answer: 1, pembahasan: "Kelembapan tinggi memperlambat pengeringan — karena kelembapan hari ini lebih tinggi, pengeringan pakaian hari ini pasti lebih lambat.", paket: 2 },
  { id: "pu37", subtes: "PU", topic: "Diagram Venn", q: "Semua peserta lomba menulis mengumpulkan naskah sebelum batas waktu. Sebagian peserta yang mengumpulkan naskah juga mengikuti sesi pelatihan. Berdasarkan pernyataan tersebut, yang pasti benar adalah…", opts: ["Semua peserta lomba menulis mengikuti pelatihan", "Sebagian peserta lomba menulis mungkin mengikuti pelatihan", "Tidak ada peserta lomba menulis yang ikut pelatihan", "Semua yang ikut pelatihan adalah peserta lomba menulis"], answer: 1, pembahasan: "Karena hanya 'sebagian' pengumpul naskah yang ikut pelatihan, tidak bisa dipastikan proporsi peserta lomba menulis yang termasuk golongan itu — hanya bisa dikatakan 'mungkin sebagian'.", paket: 2 },
  { id: "pu38", subtes: "PU", topic: "Deret", q: "Lanjutkan deret: 100, 95, 85, 70, 50, ...?", opts: ["20", "25", "30", "35"], answer: 1, pembahasan: "Selisih antarsuku berkurang 5 tiap langkah (-5,-10,-15,-20). Suku berikutnya: 50 − 25 = 25.", paket: 2 },
  { id: "pu39", subtes: "PU", topic: "Analogi", q: "TERMOMETER : SUHU = ... : ...", opts: ["Barometer : Tekanan udara", "Kalender : Bulan", "Peta : Jalan", "Jam : Menit"], answer: 0, pembahasan: "Termometer digunakan untuk mengukur suhu, sama seperti barometer digunakan untuk mengukur tekanan udara — hubungan alat ukur dan besaran yang diukur.", paket: 2 },
  { id: "pu40", subtes: "PU", topic: "Silogisme", q: "Semua anggota paduan suara yang lolos seleksi suara tampil di konser. Doni tidak tampil di konser. Maka…", opts: ["Doni pasti lolos seleksi suara", "Doni pasti tidak lolos seleksi suara", "Status seleksi Doni tidak bisa dipastikan", "Konser tidak berkaitan dengan seleksi suara"], answer: 1, pembahasan: "Modus tollens: karena Doni tidak tampil di konser (akibat tidak terjadi), maka ia pasti tidak lolos seleksi suara (sebab juga tidak terjadi).", paket: 2 },
  { id: "pu41", subtes: "PU", topic: "Penalaran Kuantitatif", q: "Sebuah keluarga membeli 24 butir telur untuk dibagi rata ke dalam 4 kotak. Keluarga lain membeli 30 butir telur untuk dibagi rata ke dalam 5 kotak. Manakah pernyataan yang tepat mengenai jumlah telur per kotak?", opts: ["Kotak keluarga pertama berisi lebih banyak telur", "Kotak keluarga kedua berisi lebih banyak telur", "Kedua kotak berisi jumlah telur yang sama", "Tidak dapat dibandingkan"], answer: 2, pembahasan: "Telur per kotak keluarga pertama = 24÷4 = 6. Telur per kotak keluarga kedua = 30÷5 = 6. Keduanya sama.", paket: 2 },
  { id: "pu42", subtes: "PU", topic: "Penalaran Kuantitatif", q: "Sebuah rak buku A memuat 45 buku dalam 3 rak sejajar. Rak buku B memuat 56 buku dalam 4 rak sejajar. Manakah rak yang rata-rata jumlah bukunya per baris lebih banyak?", opts: ["Rak A", "Rak B", "Sama banyak", "Tidak dapat ditentukan"], answer: 0, pembahasan: "Rata-rata rak A = 45÷3 = 15 buku/baris. Rata-rata rak B = 56÷4 = 14 buku/baris. Rak A lebih banyak.", paket: 2 },
  { id: "pu43", subtes: "PU", topic: "Deret", q: "Lanjutkan deret: 2, 5, 11, 23, 47, ...?", opts: ["90", "92", "94", "95"], answer: 3, pembahasan: "Polanya adalah tiap suku = 2×suku sebelumnya + 1: 2→5→11→23→47→95.", paket: 2 },
  { id: "pu44", subtes: "PU", topic: "Silogisme", q: "Tidak ada karya yang menang lomba dipublikasikan tanpa izin penulis. Karya ini dipublikasikan tanpa izin penulis. Maka karya ini…", opts: ["Pasti menang lomba", "Pasti tidak menang lomba", "Tidak bisa dipastikan menang lomba", "Tidak relevan dengan lomba"], answer: 1, pembahasan: "Premis berarti tidak ada karya pemenang yang dipublikasikan tanpa izin. Karena karya ini dipublikasikan tanpa izin, ia pasti bukan karya pemenang (modus tollens).", paket: 2 },
  { id: "pu45", subtes: "PU", topic: "Penalaran Posisi", q: "Enam kursi diberi nomor 1-6 berjajar. Kursi Rian tepat di antara kursi Sari dan kursi Tono. Kursi Sari bernomor 2. Jika Rian bernomor 3, maka kursi Tono bernomor…", opts: ["1", "4", "5", "6"], answer: 1, pembahasan: "Karena Rian (nomor 3) tepat di antara Sari (nomor 2) dan Tono, maka Tono berada di nomor 4 (sisi lain dari Rian).", paket: 2 },
  { id: "pu46", subtes: "PU", topic: "Logika Pernyataan", q: "\"Semua peserta yang terlambat tidak diperbolehkan mengikuti ujian.\" Manakah pernyataan yang senilai (ekuivalen) dengan pernyataan tersebut?", opts: ["Peserta yang tidak terlambat pasti diperbolehkan mengikuti ujian", "Peserta yang diperbolehkan mengikuti ujian pasti tidak terlambat", "Peserta yang terlambat mungkin diperbolehkan mengikuti ujian", "Semua peserta diperbolehkan mengikuti ujian"], answer: 1, pembahasan: "Pernyataan 'semua yang terlambat tidak boleh ikut ujian' ekuivalen dengan kontraposisinya: 'yang boleh ikut ujian pasti tidak terlambat'.", paket: 2 },
  { id: "pu47", subtes: "PU", topic: "Penalaran Sebab-Akibat", q: "Semakin sering mesin dirawat secara berkala, semakin kecil risiko kerusakan mendadak. Mesin A dirawat lebih sering dibanding mesin B. Maka…", opts: ["Risiko kerusakan mendadak mesin A lebih kecil dari mesin B", "Risiko kerusakan mendadak mesin A lebih besar dari mesin B", "Risiko keduanya pasti sama", "Perawatan tidak memengaruhi risiko kerusakan"], answer: 0, pembahasan: "Semakin sering dirawat, semakin kecil risiko kerusakan — karena mesin A dirawat lebih sering, risiko kerusakannya lebih kecil dari mesin B.", paket: 2 },
  { id: "pu48", subtes: "PU", topic: "Analogi", q: "KOMPAS : ARAH = ... : ...", opts: ["Timbangan : Berat", "Kalender : Warna", "Payung : Hujan", "Sepatu : Kaki"], answer: 0, pembahasan: "Kompas digunakan untuk menunjukkan arah, sama seperti timbangan digunakan untuk menunjukkan berat.", paket: 2 },
  { id: "pu49", subtes: "PU", topic: "Deret", q: "Lanjutkan deret huruf: Z, X, V, T, R, ...?", opts: ["O", "P", "Q", "N"], answer: 1, pembahasan: "Pola huruf mundur 2 langkah setiap kali: Z-2=X, X-2=V, V-2=T, T-2=R, R-2=P.", paket: 2 },
  { id: "pu50", subtes: "PU", topic: "Penalaran Kuantitatif", q: "Sebuah botol A berisi 750 ml jus dibagi rata ke 5 gelas. Botol B berisi 960 ml jus dibagi rata ke 6 gelas. Manakah gelas yang volumenya lebih banyak?", opts: ["Gelas dari botol A", "Gelas dari botol B", "Sama banyak", "Tidak dapat ditentukan"], answer: 1, pembahasan: "Volume per gelas botol A = 750÷5 = 150 ml. Volume per gelas botol B = 960÷6 = 160 ml. Gelas dari botol B lebih banyak.", paket: 2 },
  { id: "pu51", subtes: "PU", topic: "Silogisme", q: "Semua kandidat yang lolos tes kesehatan boleh melanjutkan ke tahap wawancara. Fira melanjutkan ke tahap wawancara. Maka…", opts: ["Fira pasti lolos tes kesehatan", "Fira pasti tidak lolos tes kesehatan", "Tidak bisa dipastikan status tes kesehatan Fira", "Wawancara tidak berkaitan dengan tes kesehatan"], answer: 2, pembahasan: "Premis hanya menyatakan 'lolos tes kesehatan → boleh wawancara', bukan sebaliknya. Mengikuti wawancara tidak otomatis membuktikan lolos tes kesehatan.", paket: 2 },
  { id: "pu52", subtes: "PU", topic: "Penalaran Posisi", q: "Empat toko berjejer: Toko Buku, Toko Elektronik, Toko Pakaian, Toko Sepatu. Toko Buku ada di ujung kiri. Toko Elektronik tepat di sebelah kanan Toko Buku. Toko Sepatu ada di ujung kanan. Urutan toko dari kiri ke kanan adalah…", opts: ["Toko Buku, Toko Elektronik, Toko Pakaian, Toko Sepatu", "Toko Buku, Toko Pakaian, Toko Elektronik, Toko Sepatu", "Toko Elektronik, Toko Buku, Toko Pakaian, Toko Sepatu", "Toko Buku, Toko Elektronik, Toko Sepatu, Toko Pakaian"], answer: 0, pembahasan: "Toko Buku di ujung kiri, Toko Elektronik tepat di sebelahnya, Toko Sepatu di ujung kanan, sehingga Toko Pakaian mengisi posisi ketiga.", paket: 2 },
  { id: "pu53", subtes: "PU", topic: "Deret", q: "Lanjutkan deret: 3, 6, 11, 18, 27, ...?", opts: ["36", "37", "38", "39"], answer: 2, pembahasan: "Selisih antarsuku bertambah 2 tiap langkah (3,5,7,9). Suku berikutnya: 27 + 11 = 38.", paket: 2 },
  { id: "pu54", subtes: "PU", topic: "Logika Pernyataan", q: "\"Jika target penjualan tercapai, maka bonus dibagikan.\" Ingkaran dari pernyataan tersebut adalah…", opts: ["Target penjualan tercapai dan bonus tidak dibagikan", "Target penjualan tidak tercapai dan bonus dibagikan", "Jika bonus dibagikan, target penjualan tercapai", "Target penjualan tercapai atau bonus dibagikan"], answer: 0, pembahasan: "Ingkaran dari 'jika P maka Q' adalah 'P dan bukan Q'.", paket: 2 },
  { id: "pu55", subtes: "PU", topic: "Analogi", q: "PETANI : CANGKUL = ... : ...", opts: ["Tukang kayu : Gergaji", "Dokter : Pasien", "Guru : Murid", "Penyanyi : Panggung"], answer: 0, pembahasan: "Petani menggunakan cangkul sebagai alat kerjanya, sama seperti tukang kayu menggunakan gergaji.", paket: 2 },
  { id: "pu56", subtes: "PU", topic: "Penalaran Sebab-Akibat", q: "Semakin banyak vitamin C dikonsumsi dalam batas wajar, semakin kuat daya tahan tubuh terhadap flu ringan. Andi mengonsumsi vitamin C lebih banyak dari Budi (masih dalam batas wajar). Maka…", opts: ["Daya tahan tubuh Andi terhadap flu ringan lebih kuat dari Budi", "Daya tahan tubuh Andi lebih lemah dari Budi", "Daya tahan keduanya pasti sama", "Vitamin C tidak berkaitan dengan daya tahan tubuh"], answer: 0, pembahasan: "Konsumsi vitamin C lebih banyak (dalam batas wajar) berbanding lurus dengan daya tahan tubuh — Andi mengonsumsi lebih banyak, sehingga daya tahannya lebih kuat.", paket: 2 },
  { id: "pu57", subtes: "PU", topic: "Diagram Venn", q: "Semua siswa yang mengikuti olimpiade sains lolos ke tingkat provinsi. Sebagian siswa yang lolos ke tingkat provinsi juga mendapat beasiswa. Yang pasti benar adalah…", opts: ["Semua siswa olimpiade sains mendapat beasiswa", "Sebagian siswa olimpiade sains mungkin mendapat beasiswa", "Tidak ada siswa olimpiade sains yang mendapat beasiswa", "Semua penerima beasiswa adalah siswa olimpiade sains"], answer: 1, pembahasan: "Karena hanya 'sebagian' peserta tingkat provinsi yang mendapat beasiswa, tidak bisa dipastikan proporsi siswa olimpiade sains yang termasuk golongan itu.", paket: 2 },
  { id: "pu58", subtes: "PU", topic: "Penalaran Kuantitatif", q: "Kelas A terdiri dari 32 siswa dengan 8 siswa laki-laki. Kelas B terdiri dari 28 siswa dengan 7 siswa laki-laki. Manakah kelas dengan proporsi siswa laki-laki lebih besar?", opts: ["Kelas A", "Kelas B", "Sama besar", "Tidak dapat ditentukan"], answer: 2, pembahasan: "Proporsi laki-laki kelas A = 8/32 = 25%. Proporsi laki-laki kelas B = 7/28 = 25%. Keduanya sama.", paket: 2 },
  { id: "pu59", subtes: "PU", topic: "Deret", q: "Lanjutkan deret: 1, 2, 6, 24, 120, ...?", opts: ["600", "650", "700", "720"], answer: 3, pembahasan: "Polanya adalah tiap suku dikalikan bilangan yang terus bertambah (×2,×3,×4,×5,×6): 1→2→6→24→120→720.", paket: 2 },
  { id: "pu60", subtes: "PU", topic: "Silogisme", q: "Semua produk yang lolos uji keamanan mendapat sertifikat SNI. Produk ini tidak mendapat sertifikat SNI. Maka produk ini…", opts: ["Pasti lolos uji keamanan", "Pasti tidak lolos uji keamanan", "Tidak bisa dipastikan lolos uji keamanan", "Tidak relevan dengan uji keamanan"], answer: 1, pembahasan: "Modus tollens: karena produk ini tidak mendapat sertifikat SNI (akibat tidak terjadi), maka ia pasti tidak lolos uji keamanan (sebab juga tidak terjadi).", paket: 2 },

  // ---------- Pengetahuan & Pemahaman Umum (PPU) ----------
  { id: "ppu1", subtes: "PPU", topic: "Sains Umum", q: "Efek rumah kaca terjadi ketika radiasi matahari terperangkap oleh gas-gas seperti karbon dioksida di atmosfer bumi, menyebabkan suhu permukaan bumi meningkat. Berdasarkan pernyataan tersebut, penyebab utama efek rumah kaca adalah…", opts: ["Radiasi matahari yang berkurang", "Gas-gas yang menahan radiasi matahari di atmosfer", "Rotasi bumi yang melambat", "Berkurangnya lapisan ozon"], answer: 1, pembahasan: "Teks secara eksplisit menyatakan gas-gas seperti CO2 menahan radiasi matahari di atmosfer, itulah penyebab utamanya.", paket: 1 },
  { id: "ppu2", subtes: "PPU", topic: "Geografi Indonesia", q: "Indonesia terletak di pertemuan tiga lempeng tektonik utama, yaitu lempeng Eurasia, Indo-Australia, dan Pasifik. Kondisi ini menyebabkan Indonesia…", opts: ["Bebas dari gempa bumi", "Rawan gempa bumi dan aktivitas vulkanik", "Memiliki iklim subtropis", "Tidak memiliki gunung berapi"], answer: 1, pembahasan: "Pertemuan tiga lempeng tektonik aktif membuat wilayah rawan gempa dan aktivitas vulkanik, seperti kondisi geografis Indonesia.", paket: 1 },
  { id: "ppu3", subtes: "PPU", topic: "Ekonomi Dasar", q: "Ketika permintaan suatu barang meningkat sementara jumlah barang yang tersedia tetap, maka menurut hukum ekonomi dasar, harga barang tersebut cenderung…", opts: ["Turun", "Naik", "Tetap stabil", "Tidak terpengaruh"], answer: 1, pembahasan: "Hukum permintaan-penawaran dasar: jika permintaan naik sementara pasokan tetap, harga cenderung naik.", paket: 1 },
  { id: "ppu4", subtes: "PPU", topic: "Energi Terbarukan", q: "Pembangkit Listrik Tenaga Surya (PLTS) mengubah energi matahari menjadi energi listrik melalui panel fotovoltaik. Keunggulan utama PLTS dibanding pembangkit berbahan bakar fosil adalah…", opts: ["Biaya awal yang lebih murah", "Sumber energi yang dapat diperbarui dan minim emisi", "Dapat beroperasi tanpa sinar matahari", "Tidak membutuhkan perawatan sama sekali"], answer: 1, pembahasan: "PLTS memanfaatkan energi matahari yang terus tersedia (terbarukan) dan tidak menghasilkan emisi pembakaran seperti pembangkit fosil.", paket: 1 },
  { id: "ppu5", subtes: "PPU", topic: "Sejarah Indonesia", q: "Proklamasi Kemerdekaan Indonesia dibacakan pada tanggal…", opts: ["17 Agustus 1944", "17 Agustus 1945", "17 Agustus 1946", "1 Juni 1945"], answer: 1, pembahasan: "Ini fakta sejarah baku: Proklamasi Kemerdekaan Indonesia dibacakan 17 Agustus 1945.", paket: 1 },
  { id: "ppu6", subtes: "PPU", topic: "Lingkungan", q: "Penggundulan hutan (deforestasi) di daerah hulu sungai dapat meningkatkan risiko bencana di daerah hilir berupa…", opts: ["Kekeringan permanen", "Banjir dan tanah longsor", "Peningkatan kualitas air", "Penurunan suhu udara"], answer: 1, pembahasan: "Hutan di hulu berfungsi menyerap air hujan; tanpa itu, air mengalir deras ke hilir dan memicu banjir serta longsor.", paket: 1 },
  { id: "ppu7", subtes: "PPU", topic: "Teknologi", q: "Internet of Things (IoT) adalah konsep di mana berbagai perangkat elektronik terhubung dan dapat bertukar data melalui internet. Contoh penerapan IoT dalam kehidupan sehari-hari adalah…", opts: ["Lampu rumah yang bisa dinyalakan lewat aplikasi smartphone", "Buku cetak biasa", "Kalkulator sederhana", "Surat kabar cetak"], answer: 0, pembahasan: "Lampu yang dikendalikan lewat aplikasi smartphone adalah contoh perangkat yang terhubung internet dan bisa dikendalikan jarak jauh — ciri khas IoT.", paket: 1 },
  { id: "ppu8", subtes: "PPU", topic: "Sosial-Budaya", q: "Urbanisasi adalah perpindahan penduduk dari desa ke kota. Salah satu dampak negatif urbanisasi yang tidak terkendali bagi kota adalah…", opts: ["Berkurangnya lapangan kerja di desa", "Kepadatan penduduk dan permukiman kumuh di kota", "Meningkatnya hasil pertanian", "Menurunnya jumlah penduduk kota"], answer: 1, pembahasan: "Urbanisasi tak terkendali membuat kota kelebihan penduduk tanpa infrastruktur memadai, memicu permukiman kumuh.", paket: 1 },
  { id: "ppu9", subtes: "PPU", topic: "Sains Umum", q: "Air memiliki sifat anomali, yaitu volumenya mengembang saat membeku menjadi es. Sifat ini menyebabkan…", opts: ["Es lebih padat daripada air", "Es dapat mengapung di atas air", "Air membeku pada suhu 100°C", "Es tenggelam di dalam air"], answer: 1, pembahasan: "Karena es memiliki volume lebih besar (mengembang) dari air pada massa yang sama, massa jenis es lebih kecil sehingga es mengapung.", paket: 1 },
  { id: "ppu10", subtes: "PPU", topic: "Kebijakan Publik", q: "Subsidi bahan bakar minyak (BBM) oleh pemerintah bertujuan utama untuk…", opts: ["Meningkatkan harga BBM di pasar", "Meringankan beban masyarakat terhadap harga BBM", "Mengurangi konsumsi BBM masyarakat", "Menambah pendapatan negara dari sektor BBM"], answer: 1, pembahasan: "Subsidi BBM dirancang agar harga BBM tetap terjangkau bagi masyarakat, meringankan beban pengeluaran mereka.", paket: 1 },
  { id: "ppu11", subtes: "PPU", topic: "Geografi", q: "Fenomena pulau panas perkotaan (urban heat island) terjadi karena…", opts: ["Banyaknya area hijau di perkotaan", "Permukaan beton dan aspal yang menyerap serta menahan panas", "Curah hujan yang tinggi di kota", "Suhu kota selalu lebih rendah dari desa"], answer: 1, pembahasan: "Permukaan beton dan aspal menyerap panas matahari di siang hari dan melepaskannya perlahan, membuat suhu kota lebih tinggi dari sekitarnya.", paket: 1 },
  { id: "ppu12", subtes: "PPU", topic: "Sains Umum", q: "Gempa bumi yang terjadi di dasar laut dapat memicu terjadinya…", opts: ["Tsunami", "Gerhana matahari", "El Nino", "Hujan asam"], answer: 0, pembahasan: "Gempa di dasar laut dapat menggeser lempeng secara vertikal dan mendorong kolom air di atasnya, memicu gelombang tsunami.", paket: 1 },
  { id: "ppu13", subtes: "PPU", topic: "Sains Umum", q: "Fotosintesis adalah proses tumbuhan hijau mengubah karbon dioksida dan air menjadi glukosa dan oksigen dengan bantuan cahaya matahari. Gas yang dihasilkan dari proses ini dan dilepaskan ke udara adalah…", opts: ["Karbon dioksida", "Oksigen", "Nitrogen", "Metana"], answer: 1, pembahasan: "Reaksi fotosintesis menghasilkan glukosa untuk tumbuhan dan oksigen yang dilepaskan sebagai produk sampingan ke udara.", paket: 1 },
  { id: "ppu14", subtes: "PPU", topic: "Ekonomi Dasar", q: "Inflasi adalah kondisi ketika harga barang dan jasa secara umum naik terus-menerus dalam suatu periode. Dampak langsung inflasi tinggi bagi masyarakat berpenghasilan tetap adalah…", opts: ["Daya beli meningkat", "Daya beli menurun", "Tabungan bertambah nilainya", "Tidak ada dampak apa pun"], answer: 1, pembahasan: "Saat harga naik terus-menerus namun penghasilan tetap, jumlah barang yang bisa dibeli dengan uang yang sama menjadi lebih sedikit — daya beli menurun.", paket: 1 },
  { id: "ppu15", subtes: "PPU", topic: "Kesehatan Masyarakat", q: "Vaksinasi bekerja dengan cara memperkenalkan bagian lemah/tidak aktif dari suatu patogen agar sistem imun tubuh belajar mengenalinya. Tujuan utama vaksinasi adalah…", opts: ["Menyembuhkan penyakit yang sudah parah", "Membentuk kekebalan tubuh sebelum terinfeksi", "Menghilangkan seluruh jenis virus di dunia", "Mengganti fungsi organ tubuh"], answer: 1, pembahasan: "Vaksin melatih sistem imun mengenali patogen lebih dulu, sehingga tubuh siap melawan sebelum benar-benar terinfeksi.", paket: 1 },
  { id: "ppu16", subtes: "PPU", topic: "Geografi", q: "Wilayah Indonesia yang dilalui garis khatulistiwa menyebabkan sebagian besar daerahnya memiliki iklim…", opts: ["Tropis", "Kutub", "Gurun", "Sedang"], answer: 0, pembahasan: "Daerah di sekitar garis khatulistiwa menerima sinar matahari relatif merata sepanjang tahun, menghasilkan iklim tropis.", paket: 1 },
  { id: "ppu17", subtes: "PPU", topic: "Teknologi", q: "Kecerdasan buatan (AI) adalah sistem komputer yang dirancang untuk meniru kemampuan berpikir manusia, seperti mengenali pola dan mengambil keputusan. Salah satu contoh penerapan AI dalam kehidupan sehari-hari adalah…", opts: ["Rekomendasi tontonan otomatis di aplikasi streaming", "Kalkulator manual", "Jam dinding analog", "Buku catatan kertas"], answer: 0, pembahasan: "Rekomendasi otomatis berdasarkan pola tontonan pengguna adalah contoh sistem yang 'belajar' dari data — ciri khas AI.", paket: 1 },
  { id: "ppu18", subtes: "PPU", topic: "Sains Umum", q: "Siklus air (siklus hidrologi) meliputi tahap evaporasi, kondensasi, dan presipitasi. Tahap presipitasi adalah…", opts: ["Penguapan air menjadi uap", "Pengembunan uap air menjadi awan", "Turunnya air dari awan sebagai hujan", "Air meresap ke dalam tanah"], answer: 2, pembahasan: "Presipitasi adalah tahap air jatuh dari awan ke permukaan bumi, misalnya sebagai hujan atau salju.", paket: 1 },
  { id: "ppu19", subtes: "PPU", topic: "Sosial-Budaya", q: "Keberagaman suku, agama, dan budaya di Indonesia sering disebut sebagai kekuatan sekaligus tantangan bagi persatuan bangsa. Sikap yang tepat untuk menjaga persatuan di tengah keberagaman tersebut adalah…", opts: ["Memaksakan satu budaya menjadi dominan", "Saling menghormati dan toleran terhadap perbedaan", "Mengabaikan perbedaan yang ada", "Membatasi interaksi antarkelompok budaya"], answer: 1, pembahasan: "Toleransi dan saling menghormati perbedaan adalah sikap yang menjaga persatuan di tengah keberagaman, bukan memaksakan keseragaman.", paket: 1 },
  { id: "ppu20", subtes: "PPU", topic: "Lingkungan", q: "Reduce, reuse, dan recycle adalah tiga prinsip dasar pengelolaan sampah. Prinsip 'reuse' berarti…", opts: ["Mengurangi jumlah sampah yang dihasilkan", "Menggunakan kembali barang tanpa mengubah bentuknya", "Mengolah sampah menjadi barang baru", "Membakar sampah secara langsung"], answer: 1, pembahasan: "'Reuse' berarti memakai kembali barang dalam bentuk aslinya (mis. memakai ulang botol), berbeda dari 'reduce' (mengurangi) atau 'recycle' (mendaur ulang jadi barang baru).", paket: 1 },
  { id: "ppu21", subtes: "PPU", topic: "Astronomi", q: "Bumi mengelilingi Matahari dalam waktu sekitar 365 hari, fenomena ini menjadi dasar penentuan…", opts: ["Kalender Masehi (Syamsiah)", "Zona waktu dunia", "Pasang surut air laut", "Rotasi bumi"], answer: 0, pembahasan: "Kalender Masehi (Syamsiah) didasarkan pada periode revolusi bumi mengelilingi matahari, sekitar 365 hari.", paket: 2 },
  { id: "ppu22", subtes: "PPU", topic: "Biologi", q: "Rantai makanan menggambarkan aliran energi dari produsen ke konsumen. Organisme yang berperan sebagai produsen dalam rantai makanan umumnya adalah…", opts: ["Tumbuhan hijau", "Karnivora", "Herbivora", "Pengurai"], answer: 0, pembahasan: "Tumbuhan hijau berperan sebagai produsen karena mampu menghasilkan makanannya sendiri melalui fotosintesis.", paket: 2 },
  { id: "ppu23", subtes: "PPU", topic: "Kimia Dasar", q: "Air (H2O) tersusun dari dua unsur, yaitu hidrogen dan oksigen. Proses penguraian air menjadi kedua unsur tersebut menggunakan arus listrik disebut…", opts: ["Elektrolisis", "Fotosintesis", "Respirasi", "Kondensasi"], answer: 0, pembahasan: "Elektrolisis adalah proses penguraian senyawa menggunakan arus listrik, seperti menguraikan air menjadi hidrogen dan oksigen.", paket: 2 },
  { id: "ppu24", subtes: "PPU", topic: "Sejarah Dunia", q: "Revolusi Industri yang dimulai di Inggris pada abad ke-18 ditandai dengan perubahan utama dalam…", opts: ["Sistem produksi dari tenaga manual menjadi tenaga mesin", "Sistem pemerintahan monarki menjadi republik", "Penemuan benua baru", "Perubahan bahasa resmi dunia"], answer: 0, pembahasan: "Revolusi Industri ditandai dengan pergeseran sistem produksi dari tenaga manual ke tenaga mesin.", paket: 2 },
  { id: "ppu25", subtes: "PPU", topic: "Geografi", q: "Fenomena El Nino menyebabkan sebagian wilayah Indonesia mengalami…", opts: ["Musim hujan berkepanjangan", "Musim kemarau yang lebih panjang dan kering", "Suhu udara yang menurun drastis", "Peningkatan aktivitas gunung berapi"], answer: 1, pembahasan: "El Nino umumnya menyebabkan berkurangnya curah hujan di Indonesia, sehingga musim kemarau menjadi lebih panjang dan kering.", paket: 2 },
  { id: "ppu26", subtes: "PPU", topic: "Teknologi", q: "Cloud computing memungkinkan pengguna menyimpan dan mengakses data melalui internet tanpa harus menyimpannya secara fisik di perangkat sendiri. Manfaat utama cloud computing adalah…", opts: ["Data hanya bisa diakses dari satu perangkat", "Data dapat diakses dari mana saja selama terhubung internet", "Data menjadi lebih rentan hilang", "Data harus dicetak secara berkala"], answer: 1, pembahasan: "Cloud computing memungkinkan data diakses dari berbagai perangkat selama terhubung ke internet, tanpa terikat satu perangkat fisik.", paket: 2 },
  { id: "ppu27", subtes: "PPU", topic: "Ekonomi", q: "Ketika bank sentral menaikkan suku bunga acuan, salah satu dampak yang umum terjadi adalah…", opts: ["Masyarakat cenderung lebih banyak meminjam uang", "Masyarakat cenderung lebih banyak menabung", "Harga barang otomatis turun drastis", "Nilai tukar mata uang tidak terpengaruh"], answer: 1, pembahasan: "Suku bunga acuan yang naik membuat imbal hasil menabung lebih menarik, sehingga masyarakat cenderung lebih banyak menabung.", paket: 2 },
  { id: "ppu28", subtes: "PPU", topic: "Sosiologi", q: "Gotong royong dalam masyarakat Indonesia mencerminkan nilai sosial berupa…", opts: ["Individualisme", "Kerja sama dan kebersamaan", "Persaingan antarwarga", "Ketergantungan pada pemerintah"], answer: 1, pembahasan: "Gotong royong mencerminkan nilai kerja sama dan kebersamaan dalam menyelesaikan suatu pekerjaan bersama-sama.", paket: 2 },
  { id: "ppu29", subtes: "PPU", topic: "Kesehatan", q: "Mencuci tangan dengan sabun secara rutin efektif mencegah penyebaran penyakit karena…", opts: ["Menghilangkan kuman dan bakteri di permukaan kulit tangan", "Meningkatkan suhu tubuh", "Menambah nafsu makan", "Mempercepat pertumbuhan rambut"], answer: 0, pembahasan: "Sabun membantu melepaskan dan menghilangkan kuman serta bakteri yang menempel di permukaan kulit tangan.", paket: 2 },
  { id: "ppu30", subtes: "PPU", topic: "Lingkungan", q: "Efek rumah kaca yang berlebihan dapat menyebabkan pemanasan global, yang salah satu dampaknya adalah…", opts: ["Mencairnya es di kutub dan naiknya permukaan air laut", "Menurunnya suhu bumi secara drastis", "Bertambahnya luas lapisan es di kutub", "Berkurangnya intensitas sinar matahari"], answer: 0, pembahasan: "Pemanasan global akibat efek rumah kaca berlebih menyebabkan es di kutub mencair dan permukaan air laut naik.", paket: 2 },
  { id: "ppu31", subtes: "PPU", topic: "Astronomi", q: "Gerhana bulan terjadi ketika…", opts: ["Bulan berada di antara matahari dan bumi", "Bumi berada di antara matahari dan bulan", "Matahari berada di antara bumi dan bulan", "Bulan menjauh dari bumi"], answer: 1, pembahasan: "Gerhana bulan terjadi saat bumi berada di antara matahari dan bulan, sehingga bayangan bumi menutupi bulan.", paket: 2 },
  { id: "ppu32", subtes: "PPU", topic: "Biologi", q: "Proses pernapasan manusia menghasilkan gas buang berupa…", opts: ["Oksigen", "Karbon dioksida", "Nitrogen", "Hidrogen"], answer: 1, pembahasan: "Proses pernapasan (respirasi) manusia menghasilkan karbon dioksida sebagai gas buang.", paket: 2 },
  { id: "ppu33", subtes: "PPU", topic: "Sejarah Indonesia", q: "Kongres Pemuda II pada tahun 1928 menghasilkan…", opts: ["Proklamasi Kemerdekaan", "Sumpah Pemuda", "Pembentukan BPUPKI", "Perjanjian Renville"], answer: 1, pembahasan: "Kongres Pemuda II tahun 1928 menghasilkan ikrar Sumpah Pemuda.", paket: 2 },
  { id: "ppu34", subtes: "PPU", topic: "Geografi", q: "Angin muson di Indonesia memengaruhi pergantian musim, salah satunya adalah angin muson barat yang membawa…", opts: ["Musim kemarau", "Musim hujan", "Cuaca dingin ekstrem", "Badai pasir"], answer: 1, pembahasan: "Angin muson barat yang melewati Samudra Hindia membawa banyak uap air, sehingga memicu musim hujan di Indonesia.", paket: 2 },
  { id: "ppu35", subtes: "PPU", topic: "Teknologi", q: "Enkripsi data digunakan dalam transaksi digital dengan tujuan utama…", opts: ["Mempercepat koneksi internet", "Melindungi kerahasiaan dan keamanan data", "Mengurangi ukuran file", "Meningkatkan resolusi gambar"], answer: 1, pembahasan: "Enkripsi mengubah data menjadi kode yang sulit dibaca pihak tak berwenang, sehingga melindungi kerahasiaan dan keamanan data.", paket: 2 },
  { id: "ppu36", subtes: "PPU", topic: "Ekonomi", q: "Ekonomi kreatif mengandalkan sumber daya utama berupa…", opts: ["Ide dan kreativitas manusia", "Sumber daya tambang", "Lahan pertanian yang luas", "Modal asing semata"], answer: 0, pembahasan: "Ekonomi kreatif mengandalkan ide, gagasan, dan kreativitas manusia sebagai sumber daya utamanya.", paket: 2 },
  { id: "ppu37", subtes: "PPU", topic: "Kesehatan Masyarakat", q: "Program imunisasi dasar lengkap pada anak bertujuan untuk…", opts: ["Menyembuhkan penyakit yang sudah diderita", "Mencegah penyakit menular tertentu sejak dini", "Meningkatkan berat badan anak", "Mempercepat pertumbuhan tinggi badan"], answer: 1, pembahasan: "Imunisasi dasar lengkap bertujuan mencegah anak terkena penyakit menular tertentu sejak usia dini.", paket: 2 },
  { id: "ppu38", subtes: "PPU", topic: "Lingkungan", q: "Konservasi hutan mangrove di pesisir bermanfaat untuk…", opts: ["Mempercepat abrasi pantai", "Melindungi pesisir dari abrasi dan gelombang", "Meningkatkan suhu air laut", "Mengurangi jumlah biota laut"], answer: 1, pembahasan: "Hutan mangrove berfungsi sebagai penahan alami yang melindungi wilayah pesisir dari abrasi dan gelombang.", paket: 2 },
  { id: "ppu39", subtes: "PPU", topic: "Sosial-Budaya", q: "Bhinneka Tunggal Ika sebagai semboyan bangsa Indonesia menekankan pentingnya…", opts: ["Keseragaman budaya di seluruh wilayah", "Persatuan dalam keberagaman", "Dominasi satu suku atas suku lain", "Pemisahan wilayah berdasarkan suku"], answer: 1, pembahasan: "Bhinneka Tunggal Ika menekankan persatuan bangsa meski terdiri dari beragam suku, agama, dan budaya.", paket: 2 },
  { id: "ppu40", subtes: "PPU", topic: "Sains Umum", q: "Lapisan ozon di atmosfer berfungsi melindungi bumi dari…", opts: ["Hujan asam", "Radiasi ultraviolet berlebih dari matahari", "Polusi udara perkotaan", "Gempa bumi"], answer: 1, pembahasan: "Lapisan ozon menyerap sebagian besar radiasi ultraviolet dari matahari sehingga tidak sampai berlebihan ke permukaan bumi.", paket: 2 },

  // ---------- Pemahaman Bacaan & Menulis (PBM) ----------
  { id: "pbm1", subtes: "PBM", topic: "Kepaduan Paragraf", q: "\"(1) Sepeda motor listrik semakin populer di perkotaan. (2) Kendaraan ini menggunakan baterai sebagai sumber energi utamanya. (3) Penggunaannya dapat mengurangi emisi gas buang. (4) Harga bahan bakar minyak sempat naik tahun lalu.\" Kalimat yang tidak padu dengan kalimat lainnya dalam paragraf tersebut adalah kalimat nomor…", opts: ["(1)", "(2)", "(3)", "(4)"], answer: 3, pembahasan: "Kalimat (4) membahas harga BBM, topik yang tidak berkaitan langsung dengan pembahasan utama paragraf yaitu kendaraan listrik dan manfaatnya.", paket: 1 },
  { id: "pbm2", subtes: "PBM", topic: "Keterpaduan Paragraf", q: "Manakah urutan kalimat yang membentuk paragraf paling logis dan runtut? (1) Setelah tercampur rata, adonan dituang ke dalam loyang. (2) Pertama, tepung, gula, dan telur dicampur menjadi satu. (3) Kue pun siap dipanggang di dalam oven. (4) Adonan kemudian diaduk hingga teksturnya lembut.", opts: ["(1)-(2)-(3)-(4)", "(2)-(1)-(4)-(3)", "(2)-(4)-(1)-(3)", "(1)-(3)-(2)-(4)"], answer: 2, pembahasan: "Urutan logis proses membuat kue: campur bahan (2) → aduk hingga lembut (4) → tuang ke loyang (1) → siap dipanggang (3).", paket: 1 },
  { id: "pbm3", subtes: "PBM", topic: "Tanda Baca", q: "Penggunaan tanda baca yang tepat pada kalimat berikut adalah…", opts: ["Kegiatan ini terdiri dari tiga tahap: persiapan, pelaksanaan dan evaluasi.", "Kegiatan ini terdiri dari tiga tahap: persiapan, pelaksanaan, dan evaluasi.", "Kegiatan ini, terdiri dari tiga tahap persiapan pelaksanaan dan evaluasi.", "Kegiatan ini terdiri dari tiga tahap persiapan, pelaksanaan, dan evaluasi"], answer: 1, pembahasan: "Tanda koma digunakan sebelum kata 'dan' pada perincian lebih dari dua unsur (koma Oxford dalam gaya baku Indonesia): 'persiapan, pelaksanaan, dan evaluasi'.", paket: 1 },
  { id: "pbm4", subtes: "PBM", topic: "Kalimat Utama", q: "\"Manajemen waktu belajar melibatkan penjadwalan, pemantauan progres, dan penyesuaian rencana bila terjadi keterlambatan. Semua ini bertujuan agar target belajar tercapai tepat waktu.\" Kalimat utama paragraf tersebut terletak di…", opts: ["Awal paragraf", "Tengah paragraf", "Akhir paragraf", "Tidak ada kalimat utama"], answer: 0, pembahasan: "Kalimat pertama menyampaikan gagasan utama (manajemen waktu belajar), sedangkan kalimat kedua hanya menjelaskan tujuannya — kalimat utama ada di awal.", paket: 1 },
  { id: "pbm5", subtes: "PBM", topic: "Kepaduan Antarparagraf", q: "Kata penghubung antarparagraf yang tepat untuk melanjutkan paragraf yang membahas 'keunggulan belanja daring' menuju paragraf yang membahas 'kelemahan belanja daring' adalah…", opts: ["Selain itu,", "Di sisi lain,", "Sebagai contoh,", "Dengan demikian,"], answer: 1, pembahasan: "'Di sisi lain' tepat menandai peralihan dari sisi positif ke sisi negatif suatu topik dalam dua paragraf berurutan.", paket: 1 },
  { id: "pbm6", subtes: "PBM", topic: "Menyimpulkan Data dalam Teks", q: "\"Dari 100 responden survei kepuasan, 60 responden menyatakan tidak puas, 30 responden menyatakan cukup puas, dan 10 responden menyatakan sangat puas.\" Simpulan yang paling tepat berdasarkan data tersebut adalah…", opts: ["Mayoritas responden sangat puas", "Mayoritas responden tidak puas", "Seluruh responden cukup puas", "Data tidak dapat disimpulkan"], answer: 1, pembahasan: "60 dari 100 responden (mayoritas) menyatakan tidak puas, jadi simpulan yang didukung data adalah mayoritas tidak puas.", paket: 1 },
  { id: "pbm7", subtes: "PBM", topic: "Kalimat Efektif (Menulis)", q: "Manakah revisi paling tepat untuk kalimat: \"Dikarenakan cuaca buruk sehingga keberangkatan ditunda\"?", opts: ["Dikarenakan cuaca buruk, keberangkatan ditunda.", "Karena cuaca buruk, keberangkatan ditunda.", "Karena cuaca buruk sehingga keberangkatan ditunda.", "Cuaca buruk dikarenakan keberangkatan ditunda."], answer: 1, pembahasan: "Kata 'dikarenakan' dan 'sehingga' tidak boleh dipakai bersamaan dalam satu kalimat sebab-akibat; cukup gunakan 'karena' saja.", paket: 1 },
  { id: "pbm8", subtes: "PBM", topic: "Makna Tersirat dalam Bacaan", q: "\"Meskipun laporan sekolah menyatakan seluruh kegiatan berjalan sesuai jadwal, beberapa siswa mengeluhkan banyak tugas yang belum sempat dinilai.\" Bacaan tersebut mengandung…", opts: ["Kesesuaian penuh antara laporan dan kondisi sebenarnya", "Kemungkinan adanya kesenjangan antara laporan dan kondisi sebenarnya", "Bukti bahwa laporan tersebut salah total", "Tidak ada masalah pada kegiatan sekolah"], answer: 1, pembahasan: "Ada kesenjangan antara laporan resmi (semua sesuai jadwal) dan keluhan siswa (tugas belum dinilai) — menunjukkan kemungkinan laporan tidak sepenuhnya mencerminkan kondisi nyata.", paket: 1 },
  { id: "pbm9", subtes: "PBM", topic: "Struktur Paragraf", q: "Sebuah paragraf yang baik umumnya terdiri atas kalimat utama dan…", opts: ["Kalimat penjelas yang mendukung kalimat utama", "Kalimat acak tanpa hubungan", "Kalimat utama yang berulang", "Judul paragraf"], answer: 0, pembahasan: "Struktur paragraf standar terdiri atas kalimat utama (gagasan inti) dan kalimat-kalimat penjelas yang mendukungnya.", paket: 1 },
  { id: "pbm10", subtes: "PBM", topic: "Revisi Kalimat", q: "Kalimat manakah yang paling tepat digunakan dalam laporan resmi?", opts: ["Hasil uji nunjukin kalo kualitas produknya udah sesuai standar.", "Hasil uji menunjukkan bahwa kualitas produk telah sesuai standar.", "Hasil uji nunjukin kualitas produk sesuai standar udah.", "Kualitas produknya, sesuai standar, hasil uji nunjukin."], answer: 1, pembahasan: "Laporan resmi menuntut ragam bahasa baku, bukan ragam lisan/informal seperti 'nunjukin', 'kalo', atau 'udah'.", paket: 1 },
  { id: "pbm11", subtes: "PBM", topic: "Kepaduan Paragraf", q: "\"Panitia menata dekorasi ruangan dengan hati-hati. ___, mereka memastikan setiap perlengkapan siap sebelum acara dimulai.\" Kata penghubung yang tepat untuk melengkapi kalimat tersebut adalah…", opts: ["Sebaliknya", "Selain itu", "Meskipun demikian", "Padahal"], answer: 1, pembahasan: "'Selain itu' tepat untuk menambahkan informasi sejenis (kehati-hatian dalam menata dan memastikan kesiapan) yang sejalan dengan kalimat sebelumnya.", paket: 1 },
  { id: "pbm12", subtes: "PBM", topic: "Menulis: Kesesuaian Subjek-Predikat", q: "Kalimat yang memiliki struktur subjek-predikat yang tepat adalah…", opts: ["Bagi seluruh peserta acara harus membawa kartu identitas.", "Seluruh peserta acara harus membawa kartu identitas.", "Untuk seluruh peserta acara yang harus membawa kartu identitas.", "Yang seluruh peserta acara harus membawa kartu identitas."], answer: 1, pembahasan: "Subjek 'Seluruh peserta acara' langsung diikuti predikat 'harus membawa' tanpa kata depan ('bagi', 'untuk', 'yang') yang justru mengaburkan subjek kalimat.", paket: 1 },
  { id: "pbm13", subtes: "PBM", topic: "Ide Pokok", q: "\"Membaca buku secara rutin dapat memperkaya kosakata, meningkatkan kemampuan berpikir kritis, dan memperluas wawasan seseorang.\" Ide pokok kalimat tersebut adalah…", opts: ["Kerugian membaca buku", "Manfaat membaca buku secara rutin", "Cara memilih buku yang baik", "Sejarah perkembangan buku"], answer: 1, pembahasan: "Kalimat menyebutkan tiga manfaat membaca (kosakata, berpikir kritis, wawasan) — itulah gagasan utamanya.", paket: 1 },
  { id: "pbm14", subtes: "PBM", topic: "Kalimat Tidak Padu", q: "(1) Olahraga rutin bermanfaat menjaga kesehatan jantung. (2) Aktivitas fisik juga membantu mengurangi stres. (3) Banyak orang memilih berolahraga di pagi hari. (4) Harga alat olahraga cenderung mahal di kota besar. Kalimat yang tidak padu adalah kalimat nomor…", opts: ["(1)", "(2)", "(3)", "(4)"], answer: 3, pembahasan: "Kalimat (4) membahas harga alat olahraga, tidak berkaitan dengan topik utama paragraf yaitu manfaat dan kebiasaan berolahraga.", paket: 1 },
  { id: "pbm15", subtes: "PBM", topic: "Ejaan", q: "Penulisan yang sesuai kaidah ejaan adalah…", opts: ["Kegiatan tersebut di laksanakan minggu depan.", "Kegiatan tersebut dilaksanakan minggu depan.", "Kegiatan tersebut dilaksana kan minggu depan.", "Kegiatan tersebut di-laksanakan minggu depan."], answer: 1, pembahasan: "Kata berimbuhan seperti 'dilaksanakan' ditulis serangkai, bukan dipisah atau diberi tanda hubung.", paket: 1 },
  { id: "pbm16", subtes: "PBM", topic: "Simpulan Paragraf", q: "\"Tidur yang cukup membantu tubuh memulihkan energi dan meningkatkan daya konsentrasi. Kurang tidur dalam waktu lama dapat menurunkan produktivitas.\" Simpulan yang tepat adalah…", opts: ["Tidur cukup mendukung produktivitas seseorang", "Tidur tidak berkaitan dengan produktivitas", "Kurang tidur selalu meningkatkan energi", "Produktivitas hanya dipengaruhi oleh makanan"], answer: 0, pembahasan: "Kedua kalimat sama-sama mengaitkan kualitas tidur dengan produktivitas — simpulannya tidur cukup mendukung produktivitas.", paket: 1 },
  { id: "pbm17", subtes: "PBM", topic: "Kalimat Efektif", q: "Manakah kalimat yang paling efektif?", opts: ["Menurut saya pribadi, saya rasa acara ini berjalan lancar.", "Menurut saya, acara ini berjalan lancar.", "Saya pribadi menurut saya acara ini lancar.", "Acara ini menurut saya pribadi rasanya lancar."], answer: 1, pembahasan: "'Menurut saya' sudah cukup untuk menyatakan pendapat pribadi; menambahkan 'pribadi' dan 'saya rasa' sekaligus jadi berlebihan (redundan).", paket: 1 },
  { id: "pbm18", subtes: "PBM", topic: "Hubungan Antarkalimat", q: "\"Panitia mengecek seluruh peralatan sebelum acara dimulai. Pengecekan ini mencegah kendala teknis saat acara berlangsung.\" Hubungan antara kedua kalimat tersebut adalah…", opts: ["Pertentangan", "Tujuan-akibat", "Perbandingan", "Tidak berkaitan"], answer: 1, pembahasan: "Kalimat kedua menjelaskan tujuan/manfaat dari tindakan di kalimat pertama — hubungan tujuan-akibat.", paket: 1 },
  { id: "pbm19", subtes: "PBM", topic: "Kata Baku dalam Kalimat", q: "Kalimat yang menggunakan kata baku dengan tepat adalah…", opts: ["Kami akan menganalisa data tersebut minggu depan.", "Kami akan menganalisis data tersebut minggu depan.", "Kami akan menganalisakan data tersebut minggu depan.", "Kami akan analisa data tersebut minggu depan."], answer: 1, pembahasan: "Bentuk baku sesuai KBBI adalah 'menganalisis', bukan 'menganalisa' atau 'menganalisakan'.", paket: 1 },
  { id: "pbm20", subtes: "PBM", topic: "Makna Tersirat", q: "\"Walaupun harga bahan baku naik, perusahaan tetap mempertahankan kualitas produk tanpa menaikkan harga jual.\" Makna tersirat dari kalimat tersebut adalah…", opts: ["Perusahaan mengorbankan kualitas demi harga", "Perusahaan memilih menjaga kepuasan pelanggan meski margin untung menurun", "Harga jual pasti naik mengikuti bahan baku", "Kualitas produk tidak lagi diperhatikan"], answer: 1, pembahasan: "Kata 'walaupun' menyiratkan perusahaan tetap memilih menjaga kualitas dan harga meski itu menekan keuntungan mereka.", paket: 1 },
  { id: "pbm21", subtes: "PBM", topic: "Ide Pokok", q: "\"Berkebun di rumah dapat menjadi sarana relaksasi, sumber sayuran segar, dan kegiatan yang ramah lingkungan.\" Ide pokok kalimat tersebut adalah…", opts: ["Kerugian berkebun di rumah", "Manfaat berkebun di rumah", "Sejarah berkebun", "Jenis-jenis tanaman kebun"], answer: 1, pembahasan: "Kalimat menyebutkan tiga manfaat berkebun di rumah — itulah gagasan utamanya.", paket: 2 },
  { id: "pbm22", subtes: "PBM", topic: "Kalimat Tidak Padu", q: "(1) Bersepeda rutin baik untuk kesehatan jantung. (2) Kegiatan ini juga membantu mengurangi polusi udara. (3) Banyak kota mulai membangun jalur sepeda khusus. (4) Harga sepeda impor cenderung lebih mahal. Kalimat yang tidak padu adalah kalimat nomor…", opts: ["(1)", "(2)", "(3)", "(4)"], answer: 3, pembahasan: "Kalimat (4) membahas harga sepeda impor, tidak berkaitan dengan topik utama paragraf yaitu manfaat dan dukungan terhadap bersepeda.", paket: 2 },
  { id: "pbm23", subtes: "PBM", topic: "Tanda Baca", q: "Penggunaan tanda baca yang tepat pada kalimat berikut adalah…", opts: ["Sekolah menyediakan tiga fasilitas: perpustakaan, laboratorium dan kantin.", "Sekolah menyediakan tiga fasilitas: perpustakaan, laboratorium, dan kantin.", "Sekolah menyediakan tiga fasilitas, perpustakaan laboratorium dan kantin.", "Sekolah menyediakan tiga fasilitas perpustakaan, laboratorium, dan kantin"], answer: 1, pembahasan: "Tanda koma dipakai sebelum kata 'dan' pada perincian lebih dari dua unsur, dan tanda titik dua mengawali rincian.", paket: 2 },
  { id: "pbm24", subtes: "PBM", topic: "Kalimat Utama", q: "\"Perpustakaan sekolah menyediakan ribuan judul buku, ruang baca yang nyaman, dan akses internet gratis bagi siswa. Fasilitas ini mendukung minat baca siswa.\" Kalimat utama paragraf tersebut terletak di…", opts: ["Awal paragraf", "Tengah paragraf", "Akhir paragraf", "Tidak ada kalimat utama"], answer: 0, pembahasan: "Kalimat pertama menyampaikan gagasan utama (fasilitas perpustakaan), sedangkan kalimat kedua hanya menjelaskan dampaknya.", paket: 2 },
  { id: "pbm25", subtes: "PBM", topic: "Kepaduan Antarparagraf", q: "Kata penghubung antarparagraf yang tepat untuk melanjutkan paragraf yang membahas 'manfaat tidur cukup' menuju paragraf yang membahas 'akibat kurang tidur' adalah…", opts: ["Selain itu,", "Sebaliknya,", "Sebagai contoh,", "Dengan demikian,"], answer: 1, pembahasan: "'Sebaliknya' tepat menandai peralihan dari sisi positif ke sisi negatif suatu topik dalam dua paragraf berurutan.", paket: 2 },
  { id: "pbm26", subtes: "PBM", topic: "Menyimpulkan Data", q: "\"Dari 200 pengunjung pameran, 120 orang menyatakan puas, 50 orang cukup puas, dan 30 orang tidak puas.\" Simpulan yang paling tepat berdasarkan data tersebut adalah…", opts: ["Mayoritas pengunjung tidak puas", "Mayoritas pengunjung menyatakan puas", "Seluruh pengunjung cukup puas", "Data tidak dapat disimpulkan"], answer: 1, pembahasan: "120 dari 200 pengunjung (mayoritas) menyatakan puas, sehingga simpulan yang didukung data adalah mayoritas pengunjung puas.", paket: 2 },
  { id: "pbm27", subtes: "PBM", topic: "Kalimat Efektif", q: "Manakah revisi paling tepat untuk kalimat: \"Disebabkan karena hujan lebat sehingga jalan tergenang\"?", opts: ["Disebabkan karena hujan lebat, jalan tergenang.", "Karena hujan lebat, jalan tergenang.", "Karena hujan lebat sehingga jalan tergenang.", "Jalan tergenang disebabkan karena hujan lebat sehingga."], answer: 1, pembahasan: "Kata 'disebabkan karena' dan 'sehingga' tidak boleh dipakai bersamaan dalam satu kalimat sebab-akibat; cukup gunakan 'karena' saja.", paket: 2 },
  { id: "pbm28", subtes: "PBM", topic: "Makna Tersirat", q: "\"Meskipun hasil survei menyatakan pelayanan sudah memuaskan, beberapa pelanggan tetap mengeluhkan lambatnya waktu respons.\" Bacaan tersebut mengandung…", opts: ["Kesesuaian penuh antara survei dan kondisi nyata", "Kemungkinan adanya kesenjangan antara survei dan kondisi nyata", "Bukti bahwa survei tersebut salah total", "Tidak ada masalah pada pelayanan"], answer: 1, pembahasan: "Ada kesenjangan antara hasil survei (memuaskan) dan keluhan nyata pelanggan (lambat merespons) — menunjukkan kemungkinan survei belum sepenuhnya mencerminkan kondisi nyata.", paket: 2 },
  { id: "pbm29", subtes: "PBM", topic: "Struktur Paragraf", q: "Paragraf deduktif adalah paragraf yang…", opts: ["Kalimat utamanya berada di awal paragraf", "Kalimat utamanya berada di akhir paragraf", "Tidak memiliki kalimat utama", "Kalimat utamanya berada di tengah paragraf"], answer: 0, pembahasan: "Paragraf deduktif memiliki kalimat utama di awal, diikuti kalimat-kalimat penjelas.", paket: 2 },
  { id: "pbm30", subtes: "PBM", topic: "Revisi Kalimat", q: "Kalimat manakah yang paling tepat digunakan dalam surat resmi?", opts: ["Kami mohon maaf atas keterlambatan ini ya.", "Kami mohon maaf atas keterlambatan ini.", "Maaf ya atas keterlambatan ini.", "Keterlambatan ini, kami mohon maaf ya."], answer: 1, pembahasan: "Surat resmi menuntut ragam bahasa baku dan formal, tanpa partikel percakapan seperti 'ya'.", paket: 2 },
  { id: "pbm31", subtes: "PBM", topic: "Kepaduan Paragraf", q: "\"Petugas kebersihan menyapu jalan setiap pagi. ___, mereka juga mengangkut sampah ke tempat pembuangan akhir.\" Kata penghubung yang tepat untuk melengkapi kalimat tersebut adalah…", opts: ["Sebaliknya", "Selain itu", "Meskipun demikian", "Padahal"], answer: 1, pembahasan: "'Selain itu' tepat menambahkan informasi sejenis (tugas lain petugas kebersihan) yang sejalan dengan kalimat sebelumnya.", paket: 2 },
  { id: "pbm32", subtes: "PBM", topic: "Menulis: Subjek-Predikat", q: "Kalimat yang memiliki struktur subjek-predikat yang tepat adalah…", opts: ["Bagi seluruh siswa harus mengikuti upacara.", "Seluruh siswa harus mengikuti upacara.", "Untuk seluruh siswa yang harus mengikuti upacara.", "Yang seluruh siswa harus mengikuti upacara."], answer: 1, pembahasan: "Subjek 'Seluruh siswa' langsung diikuti predikat 'harus mengikuti' tanpa kata depan yang mengaburkan subjek kalimat.", paket: 2 },
  { id: "pbm33", subtes: "PBM", topic: "Ide Pokok", q: "\"Transportasi umum yang nyaman dan terjangkau dapat mengurangi kemacetan serta polusi udara di perkotaan.\" Ide pokok kalimat tersebut adalah…", opts: ["Kerugian transportasi umum", "Manfaat transportasi umum yang nyaman dan terjangkau", "Sejarah transportasi umum", "Jenis kendaraan umum"], answer: 1, pembahasan: "Kalimat menjelaskan manfaat transportasi umum yang nyaman dan terjangkau — itulah gagasan utamanya.", paket: 2 },
  { id: "pbm34", subtes: "PBM", topic: "Ejaan", q: "Penulisan yang sesuai kaidah ejaan adalah…", opts: ["Kegiatan itu di adakan setiap bulan.", "Kegiatan itu diadakan setiap bulan.", "Kegiatan itu di-adakan setiap bulan.", "Kegiatan itu diada kan setiap bulan."], answer: 1, pembahasan: "Kata berimbuhan seperti 'diadakan' ditulis serangkai, bukan dipisah atau diberi tanda hubung.", paket: 2 },
  { id: "pbm35", subtes: "PBM", topic: "Hubungan Antarkalimat", q: "\"Dokter memeriksa hasil rontgen pasien dengan saksama. Pemeriksaan ini menentukan langkah pengobatan selanjutnya.\" Hubungan antara kedua kalimat tersebut adalah…", opts: ["Pertentangan", "Tujuan-akibat", "Perbandingan", "Tidak berkaitan"], answer: 1, pembahasan: "Kalimat kedua menjelaskan tujuan/manfaat dari tindakan di kalimat pertama — hubungan tujuan-akibat.", paket: 2 },
  { id: "pbm36", subtes: "PBM", topic: "Kata Baku", q: "Kalimat yang menggunakan kata baku dengan tepat adalah…", opts: ["Kami akan mensosialisasikan program baru ini.", "Kami akan mensosialisasi program baru ini.", "Kami akan sosialisasikan program baru ini.", "Kami akan mensosialisakan program baru ini."], answer: 0, pembahasan: "Bentuk baku sesuai kaidah pembentukan kata adalah 'mensosialisasikan' (me- + sosialisasi + -kan).", paket: 2 },
  { id: "pbm37", subtes: "PBM", topic: "Simpulan Paragraf", q: "\"Menabung sedikit demi sedikit sejak muda membantu seseorang memiliki cadangan dana yang cukup saat pensiun.\" Simpulan yang tepat adalah…", opts: ["Menabung sejak muda bermanfaat untuk masa pensiun", "Menabung hanya perlu dilakukan menjelang pensiun", "Dana pensiun tidak berkaitan dengan tabungan", "Menabung tidak memengaruhi masa depan"], answer: 0, pembahasan: "Kalimat menunjukkan manfaat menabung sejak muda terhadap kecukupan dana di masa pensiun — itu simpulannya.", paket: 2 },
  { id: "pbm38", subtes: "PBM", topic: "Kalimat Tidak Padu", q: "(1) Membaca nyaring membantu anak mengenal kosakata baru. (2) Kegiatan ini juga mempererat kedekatan orang tua dan anak. (3) Banyak toko buku menawarkan diskon akhir tahun. (4) Membaca nyaring sebaiknya dilakukan sejak usia dini. Kalimat yang tidak padu adalah kalimat nomor…", opts: ["(1)", "(2)", "(3)", "(4)"], answer: 2, pembahasan: "Kalimat (3) membahas diskon toko buku, tidak berkaitan dengan topik utama paragraf yaitu manfaat membaca nyaring untuk anak.", paket: 2 },
  { id: "pbm39", subtes: "PBM", topic: "Makna Tersirat", q: "\"Walaupun anggaran pemasaran dipangkas, tim tetap mempertahankan kualitas konten yang dipublikasikan.\" Makna tersirat dari kalimat tersebut adalah…", opts: ["Kualitas konten dikorbankan demi anggaran", "Tim memilih menjaga kualitas meski sumber daya terbatas", "Anggaran pemasaran pasti ditambah kembali", "Konten tidak lagi dipublikasikan"], answer: 1, pembahasan: "Kata 'walaupun' menyiratkan tim tetap memilih menjaga kualitas konten meski anggaran terbatas.", paket: 2 },
  { id: "pbm40", subtes: "PBM", topic: "Kepaduan Paragraf", q: "Manakah urutan kalimat yang membentuk paragraf paling logis dan runtut? (1) Setelah dipanaskan, air kemudian dituangkan ke dalam cangkir berisi teh. (2) Pertama, air direbus hingga mendidih. (3) Teh pun siap dinikmati. (4) Seduhan teh diaduk sebentar agar rasa merata.", opts: ["(1)-(2)-(3)-(4)", "(2)-(1)-(4)-(3)", "(2)-(4)-(1)-(3)", "(1)-(3)-(2)-(4)"], answer: 1, pembahasan: "Urutan logis: air direbus (2) → dituangkan ke cangkir (1) → diaduk (4) → siap dinikmati (3).", paket: 2 },

  // ---------- Pengetahuan Kuantitatif (PK) ----------
  { id: "pk1", subtes: "PK", topic: "Aritmetika Dasar", q: "Sebuah gudang toko memiliki stok 480 dus mi instan. Jika terjual 125 dus dalam sepekan, sisa stok mi instan adalah…", opts: ["345 dus", "355 dus", "365 dus", "375 dus"], answer: 1, pembahasan: "480 − 125 = 355 dus.", paket: 1 },
  { id: "pk2", subtes: "PK", topic: "Persentase", q: "Dari 240 siswa suatu sekolah, 15% di antaranya mendapatkan beasiswa. Jumlah siswa yang mendapatkan beasiswa adalah…", opts: ["30 orang", "36 orang", "40 orang", "45 orang"], answer: 1, pembahasan: "15% × 240 = 36 orang.", paket: 1 },
  { id: "pk3", subtes: "PK", topic: "Perbandingan Sederhana", q: "Perbandingan jumlah sirup dan air dalam suatu campuran minuman adalah 2:5. Jika jumlah air yang digunakan 25 liter, jumlah sirup yang dibutuhkan adalah…", opts: ["8 liter", "10 liter", "12 liter", "15 liter"], answer: 1, pembahasan: "Sirup : Air = 2 : 5. Jika air 25 liter, maka sirup = (2/5) × 25 = 10 liter.", paket: 1 },
  { id: "pk4", subtes: "PK", topic: "Konversi Satuan", q: "1,5 ton barang sama dengan… kilogram.", opts: ["150 kg", "1.500 kg", "15.000 kg", "150.000 kg"], answer: 1, pembahasan: "1 ton = 1.000 kg, jadi 1,5 ton = 1.500 kg.", paket: 1 },
  { id: "pk5", subtes: "PK", topic: "Data & Tabel", q: "Data kehadiran siswa dalam suatu kelas: Senin 45, Selasa 48, Rabu 42, Kamis 50, Jumat 40. Rata-rata kehadiran siswa per hari adalah…", opts: ["44", "45", "46", "47"], answer: 1, pembahasan: "(45+48+42+50+40) ÷ 5 = 225 ÷ 5 = 45.", paket: 1 },
  { id: "pk6", subtes: "PK", topic: "Aljabar Dasar", q: "Jika 3x + 6 = 21, maka nilai x adalah…", opts: ["3", "4", "5", "6"], answer: 2, pembahasan: "3x + 6 = 21 → 3x = 15 → x = 5.", paket: 1 },
  { id: "pk7", subtes: "PK", topic: "Geometri Dasar", q: "Keliling sebuah lapangan berbentuk persegi dengan sisi 18 m adalah…", opts: ["54 m", "62 m", "72 m", "81 m"], answer: 2, pembahasan: "Keliling persegi = 4 × sisi = 4 × 18 = 72 m.", paket: 1 },
  { id: "pk8", subtes: "PK", topic: "Persentase", q: "Harga sebuah sepeda naik dari Rp800.000 menjadi Rp920.000. Persentase kenaikan harga tersebut adalah…", opts: ["10%", "12,5%", "15%", "20%"], answer: 2, pembahasan: "Kenaikan harga = 920.000 − 800.000 = 120.000. Persentase = 120.000/800.000 × 100% = 15%.", paket: 1 },
  { id: "pk9", subtes: "PK", topic: "Rata-rata", q: "Nilai ujian empat mata pelajaran seorang siswa adalah 80, 85, 90, dan 85. Rata-rata nilainya adalah…", opts: ["82,5", "85", "87,5", "90"], answer: 1, pembahasan: "(80+85+90+85) ÷ 4 = 340 ÷ 4 = 85.", paket: 1 },
  { id: "pk10", subtes: "PK", topic: "Perbandingan Berbalik Nilai", q: "Jika 5 orang menyelesaikan suatu pekerjaan dalam 10 hari, maka 10 orang dengan produktivitas sama akan menyelesaikan pekerjaan tersebut dalam…", opts: ["4 hari", "5 hari", "6 hari", "8 hari"], answer: 1, pembahasan: "Jumlah orang-hari tetap: 5×10 = 50. Dengan 10 orang: 50 ÷ 10 = 5 hari.", paket: 1 },
  { id: "pk11", subtes: "PK", topic: "Bilangan & Urutan", q: "Manakah urutan bilangan berikut dari yang terkecil ke terbesar: 0,45 ; 4/9 ; 0,5 ; 5/11?", opts: ["0,45 ; 4/9 ; 5/11 ; 0,5", "4/9 ; 0,45 ; 5/11 ; 0,5", "0,45 ; 5/11 ; 4/9 ; 0,5", "4/9 ; 5/11 ; 0,45 ; 0,5"], answer: 1, pembahasan: "Dalam desimal: 4/9≈0,444; 0,45; 5/11≈0,4545; 0,5 — urut naik: 4/9, 0,45, 5/11, 0,5.", paket: 1 },
  { id: "pk12", subtes: "PK", topic: "Luas Dasar", q: "Luas sebuah ruangan berbentuk persegi panjang dengan panjang 8 m dan lebar 5 m adalah…", opts: ["13 m²", "26 m²", "40 m²", "45 m²"], answer: 2, pembahasan: "Luas persegi panjang = panjang × lebar = 8 × 5 = 40 m².", paket: 1 },
  { id: "pk13", subtes: "PK", topic: "Skala/Perbandingan", q: "Sebuah resep kue membutuhkan 250 gram tepung untuk menghasilkan 20 potong kue. Jika ingin membuat 50 potong kue dengan resep yang sama, tepung yang dibutuhkan adalah…", opts: ["500 gram", "575 gram", "625 gram", "700 gram"], answer: 2, pembahasan: "Kebutuhan tepung per potong = 250 ÷ 20 = 12,5 gram. Untuk 50 potong: 12,5 × 50 = 625 gram.", paket: 1 },
  { id: "pk14", subtes: "PK", topic: "Persentase", q: "Sebuah toko memberikan diskon 25% untuk barang seharga Rp240.000. Harga yang harus dibayar setelah diskon adalah…", opts: ["Rp150.000", "Rp165.000", "Rp180.000", "Rp200.000"], answer: 2, pembahasan: "Harga setelah diskon 25% = 240.000 × (1 − 0,25) = 240.000 × 0,75 = Rp180.000.", paket: 1 },
  { id: "pk15", subtes: "PK", topic: "Barisan Aritmetika", q: "Suatu barisan aritmetika memiliki suku pertama 4 dan beda 3. Suku ke-10 barisan tersebut adalah…", opts: ["28", "31", "34", "37"], answer: 1, pembahasan: "Suku ke-n barisan aritmetika: a_n = a_1 + (n−1)d. Suku ke-10 = 4 + 9×3 = 31.", paket: 1 },
  { id: "pk16", subtes: "PK", topic: "Kecepatan", q: "Sebuah mobil menempuh jarak 180 km dalam waktu 3 jam. Kecepatan rata-rata mobil tersebut adalah…", opts: ["50 km/jam", "55 km/jam", "60 km/jam", "65 km/jam"], answer: 2, pembahasan: "Kecepatan rata-rata = jarak ÷ waktu = 180 ÷ 3 = 60 km/jam.", paket: 1 },
  { id: "pk17", subtes: "PK", topic: "Perbandingan Senilai", q: "Harga 5 kg beras adalah Rp75.000. Harga 8 kg beras dengan harga per kg yang sama adalah…", opts: ["Rp108.000", "Rp112.000", "Rp116.000", "Rp120.000"], answer: 3, pembahasan: "Harga per kg = 75.000 ÷ 5 = 15.000. Untuk 8 kg: 15.000 × 8 = Rp120.000.", paket: 1 },
  { id: "pk18", subtes: "PK", topic: "Volume Sederhana", q: "Sebuah kotak berbentuk kubus memiliki panjang sisi 6 cm. Volume kotak tersebut adalah…", opts: ["196 cm³", "216 cm³", "236 cm³", "256 cm³"], answer: 1, pembahasan: "Volume kubus = sisi³ = 6³ = 216 cm³.", paket: 1 },
  { id: "pk19", subtes: "PK", topic: "Pecahan", q: "Hasil dari 3/4 + 1/6 adalah…", opts: ["7/12", "11/12", "5/6", "4/5"], answer: 1, pembahasan: "Samakan penyebut: 3/4 = 9/12 dan 1/6 = 2/12. Jumlahnya = 9/12 + 2/12 = 11/12.", paket: 1 },
  { id: "pk20", subtes: "PK", topic: "Statistika Dasar", q: "Median dari data: 7, 3, 9, 5, 11 adalah…", opts: ["5", "7", "9", "11"], answer: 1, pembahasan: "Setelah diurutkan: 3, 5, 7, 9, 11. Median adalah nilai tengah = 7.", paket: 1 },
  { id: "pk21", subtes: "PK", topic: "Aritmetika Dasar", q: "Sebuah perpustakaan memiliki 620 buku. Jika dipinjam 145 buku, sisa buku di perpustakaan adalah…", opts: ["465", "475", "485", "495"], answer: 1, pembahasan: "620 − 145 = 475 buku.", paket: 2 },
  { id: "pk22", subtes: "PK", topic: "Persentase", q: "Dari 320 peserta seminar, 20% di antaranya adalah mahasiswa. Jumlah mahasiswa yang mengikuti seminar adalah…", opts: ["54", "58", "64", "68"], answer: 2, pembahasan: "20% × 320 = 64 orang.", paket: 2 },
  { id: "pk23", subtes: "PK", topic: "Perbandingan", q: "Perbandingan jumlah apel dan jeruk dalam sebuah keranjang adalah 3:4. Jika jumlah jeruk 28 buah, jumlah apel adalah…", opts: ["18", "21", "24", "27"], answer: 1, pembahasan: "Apel = (3/4) × 28 = 21 buah.", paket: 2 },
  { id: "pk24", subtes: "PK", topic: "Konversi Satuan", q: "2,5 jam sama dengan… menit.", opts: ["120", "130", "140", "150"], answer: 3, pembahasan: "2,5 × 60 = 150 menit.", paket: 2 },
  { id: "pk25", subtes: "PK", topic: "Data & Tabel", q: "Data penjualan buku selama 5 hari: 12, 15, 9, 18, 16. Rata-rata penjualan per hari adalah…", opts: ["13", "14", "15", "16"], answer: 1, pembahasan: "(12+15+9+18+16) ÷ 5 = 70 ÷ 5 = 14.", paket: 2 },
  { id: "pk26", subtes: "PK", topic: "Aljabar Dasar", q: "Jika 5x − 8 = 27, maka nilai x adalah…", opts: ["5", "6", "7", "8"], answer: 2, pembahasan: "5x = 35 → x = 7.", paket: 2 },
  { id: "pk27", subtes: "PK", topic: "Geometri Dasar", q: "Luas sebuah segitiga dengan alas 14 cm dan tinggi 10 cm adalah…", opts: ["60 cm²", "70 cm²", "80 cm²", "90 cm²"], answer: 1, pembahasan: "Luas segitiga = ½ × alas × tinggi = ½ × 14 × 10 = 70 cm².", paket: 2 },
  { id: "pk28", subtes: "PK", topic: "Persentase", q: "Harga sebuah tas turun dari Rp350.000 menjadi Rp280.000. Persentase penurunan harga tersebut adalah…", opts: ["15%", "20%", "25%", "30%"], answer: 1, pembahasan: "Penurunan = 70.000 ÷ 350.000 × 100% = 20%.", paket: 2 },
  { id: "pk29", subtes: "PK", topic: "Rata-rata", q: "Nilai ulangan lima mata pelajaran seorang siswa adalah 88, 92, 85, 90, dan 90. Rata-rata nilainya adalah…", opts: ["88", "89", "90", "91"], answer: 1, pembahasan: "(88+92+85+90+90) ÷ 5 = 445 ÷ 5 = 89.", paket: 2 },
  { id: "pk30", subtes: "PK", topic: "Perbandingan Berbalik Nilai", q: "Jika 8 mesin dapat menyelesaikan suatu produksi dalam 15 hari, maka 12 mesin dengan kecepatan sama akan menyelesaikan produksi tersebut dalam…", opts: ["8 hari", "9 hari", "10 hari", "12 hari"], answer: 2, pembahasan: "8×15 = 120 mesin-hari. Dengan 12 mesin: 120 ÷ 12 = 10 hari.", paket: 2 },
  { id: "pk31", subtes: "PK", topic: "Bilangan", q: "Manakah bilangan yang merupakan kelipatan persekutuan terkecil (KPK) dari 6 dan 8?", opts: ["16", "20", "24", "28"], answer: 2, pembahasan: "KPK dari 6 dan 8 adalah 24.", paket: 2 },
  { id: "pk32", subtes: "PK", topic: "Luas", q: "Luas sebuah lingkaran dengan jari-jari 7 cm (π = 22/7) adalah…", opts: ["144 cm²", "154 cm²", "164 cm²", "174 cm²"], answer: 1, pembahasan: "Luas lingkaran = π × r² = 22/7 × 7 × 7 = 154 cm².", paket: 2 },
  { id: "pk33", subtes: "PK", topic: "Kecepatan", q: "Seorang pelari menempuh jarak 400 m dalam waktu 50 detik. Kecepatan rata-rata pelari tersebut adalah…", opts: ["6 m/detik", "7 m/detik", "8 m/detik", "9 m/detik"], answer: 2, pembahasan: "Kecepatan = jarak ÷ waktu = 400 ÷ 50 = 8 m/detik.", paket: 2 },
  { id: "pk34", subtes: "PK", topic: "Perbandingan Senilai", q: "Untuk membuat 4 loyang kue dibutuhkan 800 gram tepung. Jika ingin membuat 7 loyang kue dengan takaran yang sama, tepung yang dibutuhkan adalah…", opts: ["1.200 gram", "1.300 gram", "1.400 gram", "1.500 gram"], answer: 2, pembahasan: "Tepung per loyang = 800 ÷ 4 = 200 gram. Untuk 7 loyang: 200 × 7 = 1.400 gram.", paket: 2 },
  { id: "pk35", subtes: "PK", topic: "Pecahan", q: "Hasil dari 2/3 × 3/5 adalah…", opts: ["2/5", "3/5", "6/15", "1/2"], answer: 0, pembahasan: "2/3 × 3/5 = 6/15 = 2/5 (bentuk paling sederhana).", paket: 2 },
  { id: "pk36", subtes: "PK", topic: "Statistika Dasar", q: "Modus dari data: 4, 6, 6, 7, 8, 6, 9 adalah…", opts: ["4", "6", "7", "9"], answer: 1, pembahasan: "Angka 6 muncul paling banyak (3 kali), sehingga modusnya adalah 6.", paket: 2 },
  { id: "pk37", subtes: "PK", topic: "Volume", q: "Volume sebuah balok dengan panjang 8 cm, lebar 5 cm, dan tinggi 4 cm adalah…", opts: ["140 cm³", "150 cm³", "160 cm³", "170 cm³"], answer: 2, pembahasan: "Volume balok = p × l × t = 8 × 5 × 4 = 160 cm³.", paket: 2 },
  { id: "pk38", subtes: "PK", topic: "Persentase Bertingkat", q: "Suatu barang seharga Rp500.000 didiskon 10%, kemudian harga setelah diskon didiskon lagi 10%. Harga akhir barang tersebut adalah…", opts: ["Rp400.000", "Rp405.000", "Rp410.000", "Rp450.000"], answer: 1, pembahasan: "500.000 × 0,9 = 450.000, lalu × 0,9 = Rp405.000.", paket: 2 },
  { id: "pk39", subtes: "PK", topic: "Perbandingan Berbalik Nilai", q: "Jika 6 kran mengisi kolam dalam 40 menit, maka 8 kran dengan debit sama akan mengisi kolam yang sama dalam…", opts: ["25 menit", "28 menit", "30 menit", "32 menit"], answer: 2, pembahasan: "6×40 = 240 kran-menit. Dengan 8 kran: 240 ÷ 8 = 30 menit.", paket: 2 },
  { id: "pk40", subtes: "PK", topic: "Barisan Geometri", q: "Suatu barisan geometri memiliki suku pertama 3 dan rasio 2. Suku ke-5 barisan tersebut adalah…", opts: ["36", "42", "48", "54"], answer: 2, pembahasan: "Suku ke-n barisan geometri: a_n = a_1 × r^(n-1). Suku ke-5 = 3 × 2⁴ = 48.", paket: 2 },

  // ---------- Penalaran Matematika (PM) ----------
  { id: "pm1", subtes: "PM", topic: "Volume", q: "Sebuah balok kayu berukuran panjang 4 m, lebar 0,3 m, tinggi 0,5 m. Volumenya adalah…", opts: ["0,6 m³", "0,8 m³", "1,2 m³", "6 m³"], answer: 0, pembahasan: "Volume balok = p × l × t = 4 × 0,3 × 0,5 = 0,6 m³.", paket: 1 },
  { id: "pm2", subtes: "PM", topic: "Kemiringan/Gradien", q: "Jika kemiringan (gradien) suatu tanjakan adalah 1:20, maka untuk kenaikan 2 m dibutuhkan jarak mendatar…", opts: ["10 m", "20 m", "40 m", "60 m"], answer: 2, pembahasan: "Gradien 1:20 berarti tiap 1 m naik butuh 20 m mendatar. Untuk naik 2 m: 2 × 20 = 40 m.", paket: 1 },
  { id: "pm3", subtes: "PM", topic: "Laju Kerja", q: "Suatu pekerjaan dikerjakan 8 orang selesai dalam 15 hari. Jika ingin selesai dalam 10 hari, jumlah orang yang dibutuhkan adalah…", opts: ["10", "12", "14", "16"], answer: 1, pembahasan: "Jumlah orang-hari tetap: 8×15=120. Untuk 10 hari: 120÷10 = 12 orang.", paket: 1 },
  { id: "pm4", subtes: "PM", topic: "Skala", q: "Pada sebuah peta berskala 1:200, jarak dua titik tergambar 6 cm. Jarak sebenarnya adalah…", opts: ["6 m", "12 m", "20 m", "60 m"], answer: 1, pembahasan: "Skala 1:200 berarti 1 cm gambar = 200 cm asli. 6 cm × 200 = 1.200 cm = 12 m.", paket: 1 },
  { id: "pm5", subtes: "PM", topic: "Debit Air", q: "Sebuah pompa mengalirkan air dengan debit 30 liter/menit untuk mengisi bak penampung 900 liter. Waktu yang dibutuhkan untuk mengisi penuh bak tersebut adalah…", opts: ["15 menit", "20 menit", "30 menit", "45 menit"], answer: 2, pembahasan: "Waktu = volume ÷ debit = 900 ÷ 30 = 30 menit.", paket: 1 },
  { id: "pm6", subtes: "PM", topic: "Campuran/Rasio", q: "Campuran suatu minuman menggunakan perbandingan sirup : air : es = 1 : 2 : 3. Jika total volume campuran adalah 60 liter, volume sirup yang dibutuhkan adalah…", opts: ["6 liter", "10 liter", "12 liter", "20 liter"], answer: 1, pembahasan: "Total 6 bagian (1+2+3) = 60 liter, jadi 1 bagian = 10 liter → sirup (1 bagian) = 10 liter.", paket: 1 },
  { id: "pm7", subtes: "PM", topic: "Luas", q: "Sebidang kebun berbentuk trapesium dengan sisi sejajar 40 m dan 60 m, serta tinggi 25 m. Luas kebun tersebut adalah…", opts: ["1.000 m²", "1.250 m²", "1.500 m²", "2.500 m²"], answer: 1, pembahasan: "Luas trapesium = ½ × (sisi sejajar 1 + sisi sejajar 2) × tinggi = ½ × (40+60) × 25 = 1.250 m².", paket: 1 },
  { id: "pm8", subtes: "PM", topic: "Laju Pengisian", q: "Sebuah mobil tangki mampu mengisi 45 m³ air dalam 3 jam. Dengan laju yang sama, waktu yang dibutuhkan untuk mengisi 150 m³ air adalah…", opts: ["8 jam", "9 jam", "10 jam", "12 jam"], answer: 2, pembahasan: "Laju = 45 m³ ÷ 3 jam = 15 m³/jam. Waktu untuk 150 m³ = 150 ÷ 15 = 10 jam.", paket: 1 },
  { id: "pm9", subtes: "PM", topic: "Statistika Dasar", q: "Hasil pengukuran berat lima karung beras (dalam kg): 28, 30, 27, 31, 29. Rata-rata berat karung tersebut adalah…", opts: ["28 kg", "28,5 kg", "29 kg", "29,5 kg"], answer: 2, pembahasan: "(28+30+27+31+29) ÷ 5 = 145 ÷ 5 = 29 kg.", paket: 1 },
  { id: "pm10", subtes: "PM", topic: "Persentase", q: "Anggaran suatu perusahaan sebesar Rp2.000.000.000 sudah terpakai 35%. Sisa anggaran yang belum terpakai adalah…", opts: ["Rp700.000.000", "Rp1.200.000.000", "Rp1.300.000.000", "Rp1.500.000.000"], answer: 2, pembahasan: "Sisa anggaran = 100% − 35% = 65% × Rp2.000.000.000 = Rp1.300.000.000.", paket: 1 },
  { id: "pm11", subtes: "PM", topic: "Barisan Aritmetika", q: "Sebuah tangga rumah memiliki 18 anak tangga dengan tinggi tiap anak tangga sama, total ketinggian tangga 3,6 m. Tinggi tiap anak tangga adalah…", opts: ["18 cm", "20 cm", "22 cm", "24 cm"], answer: 1, pembahasan: "Tinggi tiap anak tangga = total tinggi ÷ jumlah anak tangga = 3,6 m ÷ 18 = 0,2 m = 20 cm.", paket: 1 },
  { id: "pm12", subtes: "PM", topic: "Perbandingan Berbalik Nilai", q: "Sebuah tim yang terdiri dari 4 orang menyelesaikan suatu tugas dalam 12 hari. Jika tim ditambah menjadi 6 orang dengan produktivitas sama per orang, tugas tersebut selesai dalam…", opts: ["6 hari", "8 hari", "9 hari", "10 hari"], answer: 1, pembahasan: "Jumlah orang-hari tetap: 4×12=48. Dengan 6 orang: 48÷6 = 8 hari.", paket: 1 },
  { id: "pm13", subtes: "PM", topic: "Volume & Konversi Satuan", q: "Sebuah tangki air berbentuk tabung berdiameter 2 m dan tinggi 3,5 m (pi ~ 22/7). Volume tangki tersebut kira-kira…", opts: ["9 m³", "11 m³", "13 m³", "15 m³"], answer: 1, pembahasan: "Volume tabung = π × r² × t = 22/7 × 1² × 3,5 = 11 m³.", paket: 1 },
  { id: "pm14", subtes: "PM", topic: "Untung/Rugi", q: "Seorang pedagang membeli 1.000 buah gelas dengan harga Rp1.200/buah lalu menjualnya kembali dengan harga Rp1.500/buah untuk seluruh sisa 200 gelas yang tidak terpakai. Keuntungan dari penjualan sisa gelas tersebut adalah…", opts: ["Rp40.000", "Rp50.000", "Rp60.000", "Rp80.000"], answer: 2, pembahasan: "Untung per gelas = 1.500 − 1.200 = 300. Untuk 200 gelas: 200 × 300 = Rp60.000.", paket: 1 },
  { id: "pm15", subtes: "PM", topic: "Pythagoras", q: "Sebuah tangga disandarkan pada dinding vertikal. Jarak kaki tangga ke dinding 3 m dan tinggi tangga menyentuh dinding 4 m. Panjang tangga tersebut adalah…", opts: ["5 m", "6 m", "7 m", "8 m"], answer: 0, pembahasan: "Menurut teorema Pythagoras: panjang tangga = √(3² + 4²) = √25 = 5 m.", paket: 1 },
  { id: "pm16", subtes: "PM", topic: "Laju Pengisian", q: "Sebuah truk tangki dapat mengalirkan 6 m³ air dalam 20 menit. Dengan laju yang sama, waktu yang dibutuhkan untuk mengalirkan 27 m³ air adalah…", opts: ["60 menit", "75 menit", "90 menit", "105 menit"], answer: 2, pembahasan: "Laju = 6 m³ ÷ 20 menit = 0,3 m³/menit. Waktu untuk 27 m³ = 27 ÷ 0,3 = 90 menit.", paket: 1 },
  { id: "pm17", subtes: "PM", topic: "Perbandingan", q: "Perbandingan jumlah buku fiksi dan nonfiksi di suatu rak adalah 3:5. Jika total buku di rak tersebut 40 buah, jumlah buku nonfiksi adalah…", opts: ["15", "20", "25", "30"], answer: 2, pembahasan: "Total 8 bagian (3+5) = 40 buah, jadi 1 bagian = 5. Nonfiksi (5 bagian) = 5 × 5 = 25 buah.", paket: 1 },
  { id: "pm18", subtes: "PM", topic: "Laju Angkut", q: "Sebuah truk mengangkut hasil panen sebanyak 8 ton setiap rit dan butuh 12 menit per rit (termasuk bongkar-muat). Untuk mengangkut total 96 ton hasil panen, waktu yang dibutuhkan adalah…", opts: ["108 menit", "120 menit", "132 menit", "144 menit"], answer: 3, pembahasan: "Jumlah rit = 96 ÷ 8 = 12 rit. Waktu total = 12 × 12 menit = 144 menit.", paket: 1 },
  { id: "pm19", subtes: "PM", topic: "Skala Peta", q: "Pada peta berskala 1:5.000, jarak dua titik tergambar 8 cm. Jarak sebenarnya di lapangan adalah…", opts: ["200 m", "400 m", "800 m", "4.000 m"], answer: 1, pembahasan: "Skala 1:5.000 berarti 1 cm gambar = 5.000 cm asli. 8 cm × 5.000 = 40.000 cm = 400 m.", paket: 1 },
  { id: "pm20", subtes: "PM", topic: "Volume Galian", q: "Sebuah kolam ikan berbentuk balok dengan panjang 10 m, lebar 2 m, dan kedalaman 1,5 m akan digali. Volume tanah yang harus digali adalah…", opts: ["20 m³", "25 m³", "30 m³", "35 m³"], answer: 2, pembahasan: "Volume balok = p × l × t = 10 × 2 × 1,5 = 30 m³.", paket: 1 },
  { id: "pm21", subtes: "PM", topic: "Persentase Progres", q: "Progres pengerjaan suatu tugas kelompok pekan lalu 42% dan pekan ini bertambah 8 poin persentase. Sisa pekerjaan yang belum terselesaikan sekarang adalah…", opts: ["42%", "50%", "58%", "65%"], answer: 1, pembahasan: "Progres sekarang = 42% + 8% = 50%. Sisa yang belum selesai = 100% − 50% = 50%." },
  { id: "pm22", subtes: "PM", topic: "Kemiringan", q: "Sebuah perosotan taman bermain memiliki kemiringan (slope) 30%. Jika jarak mendatar (horizontal) dari puncak ke ujung perosotan 4 m, beda tinggi (vertikal) yang dihasilkan adalah…", opts: ["0,8 m", "1,0 m", "1,2 m", "1,4 m"], answer: 2, pembahasan: "Beda tinggi = 30% × 4 m = 1,2 m." },
  { id: "pm23", subtes: "PM", topic: "Perbandingan Berbalik Nilai", q: "Suatu pekerjaan pengecatan lapangan dikerjakan oleh 6 orang selesai dalam 8 hari. Jika hanya tersedia 4 orang dengan produktivitas sama per orang, pekerjaan tersebut akan selesai dalam…", opts: ["10 hari", "12 hari", "14 hari", "16 hari"], answer: 1, pembahasan: "Jumlah orang-hari tetap: 6×8=48. Dengan 4 orang: 48÷4 = 12 hari." },
  { id: "pm24", subtes: "PM", topic: "Luas & Kebutuhan Material", q: "Sebuah ruang aula berbentuk persegi panjang berukuran 24 m x 15 m akan dipasangi ubin. Jika 1 m² membutuhkan 40 buah ubin, total ubin yang dibutuhkan adalah…", opts: ["12.000", "13.600", "14.400", "15.200"], answer: 2, pembahasan: "Luas aula = 24 × 15 = 360 m². Kebutuhan ubin = 360 × 40 = 14.400 buah." },
  { id: "pm25", subtes: "PM", topic: "Rata-rata Tertimbang", q: "Nilai ujian tiga mata kuliah dengan bobot SKS: Statistika (3 SKS, nilai 80), Bahasa Inggris (4 SKS, nilai 85), dan Sejarah (2 SKS, nilai 75). Nilai rata-rata tertimbangnya adalah…", opts: ["79,4", "80,6", "81,1", "82,5"], answer: 2, pembahasan: "Rata-rata tertimbang = (3×80 + 4×85 + 2×75) ÷ (3+4+2) = 730 ÷ 9 ≈ 81,1." },
  // -- Level lanjutan (dua-langkah), untuk melatih ketelitian dan kecepatan berpikir --
  { id: "pm26", subtes: "PM", topic: "Gabungan Kerja", q: "Karyawan A dapat menyelesaikan suatu pekerjaan sendirian dalam 12 hari, sedangkan karyawan B dapat menyelesaikannya sendirian dalam 8 hari. Jika keduanya bekerja bersama, pekerjaan tersebut selesai dalam…", opts: ["4 hari", "4,8 hari", "5 hari", "6 hari"], answer: 1, pembahasan: "Gabungan laju kerja = 1/12 + 1/8 = 5/24 pekerjaan/hari. Waktu = 24/5 = 4,8 hari." },
  { id: "pm27", subtes: "PM", topic: "Debit Gabungan", q: "Dua pompa mengisi kolam penampung. Pompa pertama mengalirkan 40 liter/menit dan pompa kedua 60 liter/menit. Jika kolam berkapasitas 3.000 liter dan kedua pompa dinyalakan bersamaan, waktu yang dibutuhkan untuk mengisi penuh kolam adalah…", opts: ["25 menit", "30 menit", "35 menit", "40 menit"], answer: 1, pembahasan: "Gabungan debit = 40 + 60 = 100 liter/menit. Waktu = 3.000 ÷ 100 = 30 menit." },
  { id: "pm28", subtes: "PM", topic: "Persentase Bertingkat", q: "Harga sebuah kamera awalnya Rp15.000.000. Toko memberi diskon 20%, lalu dari harga setelah diskon dikenakan pajak 10%. Harga akhir yang harus dibayar adalah…", opts: ["Rp12.000.000", "Rp12.600.000", "Rp13.200.000", "Rp13.500.000"], answer: 2, pembahasan: "Setelah diskon 20%: 15.000.000 × 0,8 = 12.000.000. Setelah pajak 10%: 12.000.000 × 1,1 = Rp13.200.000." },
  { id: "pm29", subtes: "PM", topic: "Kecepatan Relatif", q: "Dua mobil berangkat dari kota yang sama menuju kota tujuan. Mobil pertama melaju 40 km/jam dan berangkat 15 menit lebih dulu dari mobil kedua yang melaju 50 km/jam. Mobil kedua akan menyusul mobil pertama setelah mobil kedua berjalan selama…", opts: ["45 menit", "1 jam", "1 jam 15 menit", "1 jam 30 menit"], answer: 1, pembahasan: "Selisih jarak saat mobil kedua mulai = 40 × 0,25 jam = 10 km. Selisih kecepatan = 50−40 = 10 km/jam. Waktu menyusul = 10 ÷ 10 = 1 jam." },
  { id: "pm30", subtes: "PM", topic: "Campuran Bertingkat", q: "Suatu adonan kue terdiri dari tepung dan gula dengan perbandingan 1:4, dibuat sebanyak 250 gram. Kemudian ditambahkan 10 gram tepung murni ke dalam adonan tersebut. Persentase tepung dalam adonan akhir adalah…", opts: ["20,0%", "21,7%", "23,1%", "25,0%"], answer: 2, pembahasan: "Tepung awal = 1/5 × 250 = 50 gram. Setelah ditambah 10 gram: 60 gram tepung dari 260 gram total = 23,1%." },
  { id: "pm31", subtes: "PM", topic: "Luas Komposit", q: "Sebuah taman berbentuk persegi panjang berukuran 20 m x 15 m, di dalamnya terdapat kolam berbentuk lingkaran berdiameter 7 m (π ≈ 22/7). Luas taman di luar kolam (area yang bisa ditanami rumput) adalah…", opts: ["251,5 m²", "261,5 m²", "271,5 m²", "281,5 m²"], answer: 1, pembahasan: "Luas taman = 20×15 = 300 m². Luas kolam = 22/7 × 3,5² = 38,5 m². Luas rumput = 300 − 38,5 = 261,5 m²." },
  { id: "pm32", subtes: "PM", topic: "Skala Volume", q: "Sebuah model miniatur mobil dibuat dengan skala panjang 1:50. Jika volume salah satu komponen pada model adalah 2.000 cm³, volume komponen tersebut pada mobil sebenarnya adalah… (volume berskala pangkat tiga dari skala panjang, 1 m³ = 1.000.000 cm³)", opts: ["200 m³", "225 m³", "250 m³", "275 m³"], answer: 2, pembahasan: "Skala volume = (skala panjang)³ = 50³ = 125.000. Volume asli = 2.000 cm³ × 125.000 = 250.000.000 cm³ = 250 m³." },
  { id: "pm33", subtes: "PM", topic: "Perbandingan Berbalik Nilai Bertingkat", q: "Suatu pekerjaan direncanakan selesai oleh 10 orang dalam 24 hari. Setelah 6 hari bekerja, ditambahkan 5 orang baru dengan produktivitas sama. Sisa pekerjaan akan selesai dalam waktu tambahan…", opts: ["10 hari", "12 hari", "14 hari", "15 hari"], answer: 1, pembahasan: "Total kerja = 10×24=240 orang-hari. Setelah 6 hari (10 orang) terpakai 60 orang-hari, sisa 180 orang-hari. Dengan 15 orang: 180÷15 = 12 hari." },
  { id: "pm34", subtes: "PM", topic: "Bunga Tunggal", q: "Seseorang meminjam Rp200.000.000 dengan bunga tunggal (simple interest) 8% per tahun untuk modal usaha. Total yang harus dibayar setelah 3 tahun adalah…", opts: ["Rp232.000.000", "Rp240.000.000", "Rp248.000.000", "Rp256.000.000"], answer: 2, pembahasan: "Bunga per tahun = 8% × 200.000.000 = 16.000.000. Untuk 3 tahun: 3 × 16.000.000 = 48.000.000. Total = 200.000.000 + 48.000.000 = Rp248.000.000." },
  { id: "pm35", subtes: "PM", topic: "Kebutuhan & Biaya Material", q: "Kebutuhan kardus pengemasan adalah 120 lembar per 1 m³ ruang barang. Jika volume barang yang akan dikemas 4,5 m³ dan harga kardus Rp16.000 per lembar, total biaya kardus yang dibutuhkan adalah…", opts: ["Rp7.920.000", "Rp8.640.000", "Rp9.360.000", "Rp10.080.000"], answer: 1, pembahasan: "Kebutuhan kardus = 120 × 4,5 = 540 lembar. Biaya = 540 × Rp16.000 = Rp8.640.000." },
  { id: "pm36", subtes: "PM", topic: "Volume", q: "Sebuah akuarium berbentuk balok berukuran panjang 80 cm, lebar 40 cm, dan tinggi 50 cm akan diisi air hingga penuh. Volume air yang dibutuhkan adalah…", opts: ["120.000 cm³", "140.000 cm³", "160.000 cm³", "180.000 cm³"], answer: 2, pembahasan: "Volume balok = p × l × t = 80 × 40 × 50 = 160.000 cm³.", paket: 2 },
  { id: "pm37", subtes: "PM", topic: "Kemiringan", q: "Jika kemiringan suatu talang air adalah 1:25, maka untuk penurunan 4 m dibutuhkan jarak mendatar…", opts: ["75 m", "90 m", "100 m", "120 m"], answer: 2, pembahasan: "4 × 25 = 100 m.", paket: 2 },
  { id: "pm38", subtes: "PM", topic: "Laju Kerja", q: "Suatu pekerjaan dikerjakan 6 orang selesai dalam 18 hari. Jika ingin selesai dalam 12 hari, jumlah orang yang dibutuhkan adalah…", opts: ["7", "8", "9", "10"], answer: 2, pembahasan: "6×18 = 108 orang-hari. Untuk 12 hari: 108 ÷ 12 = 9 orang.", paket: 2 },
  { id: "pm39", subtes: "PM", topic: "Skala", q: "Pada sebuah peta berskala 1:400, jarak dua titik tergambar 9 cm. Jarak sebenarnya adalah…", opts: ["24 m", "30 m", "36 m", "40 m"], answer: 2, pembahasan: "9 × 400 = 3.600 cm = 36 m.", paket: 2 },
  { id: "pm40", subtes: "PM", topic: "Debit", q: "Sebuah keran mengalirkan air dengan debit 25 liter/menit untuk mengisi tangki 1.000 liter. Waktu yang dibutuhkan untuk mengisi penuh tangki tersebut adalah…", opts: ["30 menit", "35 menit", "40 menit", "45 menit"], answer: 2, pembahasan: "1.000 ÷ 25 = 40 menit.", paket: 2 },
  { id: "pm41", subtes: "PM", topic: "Campuran/Rasio", q: "Campuran suatu pupuk menggunakan perbandingan nitrogen : fosfor : kalium = 2 : 1 : 1. Jika total campuran 80 kg, jumlah nitrogen yang dibutuhkan adalah…", opts: ["20 kg", "30 kg", "40 kg", "50 kg"], answer: 2, pembahasan: "Total 4 bagian = 80 kg, jadi 1 bagian = 20 kg. Nitrogen (2 bagian) = 40 kg.", paket: 2 },
  { id: "pm42", subtes: "PM", topic: "Luas", q: "Sebidang taman berbentuk trapesium dengan sisi sejajar 30 m dan 50 m, serta tinggi 20 m. Luas taman tersebut adalah…", opts: ["700 m²", "750 m²", "800 m²", "850 m²"], answer: 2, pembahasan: "Luas trapesium = ½ × (30+50) × 20 = 800 m².", paket: 2 },
  { id: "pm43", subtes: "PM", topic: "Laju Pengisian", q: "Sebuah pompa mampu mengosongkan 60 m³ air dalam 4 jam. Dengan laju yang sama, waktu yang dibutuhkan untuk mengosongkan 105 m³ air adalah…", opts: ["6 jam", "6,5 jam", "7 jam", "7,5 jam"], answer: 2, pembahasan: "Laju = 60 ÷ 4 = 15 m³/jam. Waktu untuk 105 m³ = 105 ÷ 15 = 7 jam.", paket: 2 },
  { id: "pm44", subtes: "PM", topic: "Statistika Dasar", q: "Hasil pengukuran tinggi lima tanaman (dalam cm): 24, 28, 22, 30, 26. Rata-rata tinggi tanaman tersebut adalah…", opts: ["25 cm", "26 cm", "27 cm", "28 cm"], answer: 1, pembahasan: "(24+28+22+30+26) ÷ 5 = 130 ÷ 5 = 26 cm.", paket: 2 },
  { id: "pm45", subtes: "PM", topic: "Persentase", q: "Anggaran suatu yayasan sebesar Rp500.000.000 sudah terpakai 42%. Sisa anggaran yang belum terpakai adalah…", opts: ["Rp250.000.000", "Rp270.000.000", "Rp290.000.000", "Rp310.000.000"], answer: 2, pembahasan: "Sisa = 58% × Rp500.000.000 = Rp290.000.000.", paket: 2 },
  { id: "pm46", subtes: "PM", topic: "Barisan Aritmetika", q: "Sebuah tangga darurat memiliki 20 anak tangga dengan tinggi tiap anak tangga sama, total ketinggian tangga 4 m. Tinggi tiap anak tangga adalah…", opts: ["18 cm", "20 cm", "22 cm", "24 cm"], answer: 1, pembahasan: "400 cm ÷ 20 = 20 cm.", paket: 2 },
  { id: "pm47", subtes: "PM", topic: "Perbandingan Berbalik Nilai", q: "Sebuah tim yang terdiri dari 5 orang menyelesaikan suatu proyek dalam 16 hari. Jika tim ditambah menjadi 8 orang dengan produktivitas sama per orang, proyek tersebut selesai dalam…", opts: ["8 hari", "9 hari", "10 hari", "12 hari"], answer: 2, pembahasan: "5×16 = 80 orang-hari. Dengan 8 orang: 80 ÷ 8 = 10 hari.", paket: 2 },
  { id: "pm48", subtes: "PM", topic: "Volume & Konversi Satuan", q: "Sebuah drum berbentuk tabung berdiameter 1,4 m dan tinggi 2 m (pi ~ 22/7). Volume drum tersebut kira-kira…", opts: ["2,8 m³", "3,08 m³", "3,2 m³", "3,5 m³"], answer: 1, pembahasan: "Volume tabung = π × r² × t = 22/7 × 0,7² × 2 = 3,08 m³.", paket: 2 },
  { id: "pm49", subtes: "PM", topic: "Untung/Rugi", q: "Seorang pedagang membeli 500 buah pensil dengan harga Rp1.000/buah lalu menjualnya kembali dengan harga Rp1.300/buah untuk seluruh sisa 150 pensil yang tidak terpakai. Keuntungan dari penjualan sisa pensil tersebut adalah…", opts: ["Rp35.000", "Rp40.000", "Rp45.000", "Rp50.000"], answer: 2, pembahasan: "Untung per pensil = 1.300 − 1.000 = 300. Untuk 150 pensil: 300 × 150 = Rp45.000.", paket: 2 },
  { id: "pm50", subtes: "PM", topic: "Pythagoras", q: "Sebuah layang-layang memiliki tinggi tegak lurus ke tanah 12 m, sedangkan jarak orang yang memegang benang ke titik proyeksi layang-layang di tanah adalah 5 m. Panjang benang layang-layang tersebut adalah…", opts: ["12 m", "13 m", "14 m", "15 m"], answer: 1, pembahasan: "Panjang benang = √(12² + 5²) = √169 = 13 m.", paket: 2 },
  { id: "pm51", subtes: "PM", topic: "Gabungan Kerja", q: "Karyawan C dapat menyelesaikan suatu pekerjaan sendirian dalam 15 hari, sedangkan karyawan D dapat menyelesaikannya sendirian dalam 10 hari. Jika keduanya bekerja bersama, pekerjaan tersebut selesai dalam…", opts: ["5 hari", "6 hari", "7 hari", "8 hari"], answer: 1, pembahasan: "Gabungan laju = 1/15 + 1/10 = 1/6 pekerjaan/hari. Waktu = 6 hari.", paket: 2 },
  { id: "pm52", subtes: "PM", topic: "Debit Gabungan", q: "Dua keran mengisi bak penampung. Keran pertama mengalirkan 20 liter/menit dan keran kedua 30 liter/menit. Jika bak berkapasitas 1.000 liter dan kedua keran dinyalakan bersamaan, waktu yang dibutuhkan untuk mengisi penuh bak tersebut adalah…", opts: ["16 menit", "18 menit", "20 menit", "22 menit"], answer: 2, pembahasan: "Gabungan debit = 50 liter/menit. Waktu = 1.000 ÷ 50 = 20 menit.", paket: 2 },
  { id: "pm53", subtes: "PM", topic: "Persentase Bertingkat", q: "Harga sebuah laptop awalnya Rp12.000.000. Toko memberi diskon 15%, lalu dari harga setelah diskon dikenakan biaya admin 5%. Harga akhir yang harus dibayar adalah…", opts: ["Rp10.200.000", "Rp10.500.000", "Rp10.710.000", "Rp10.900.000"], answer: 2, pembahasan: "12.000.000 × 0,85 = 10.200.000, lalu × 1,05 = Rp10.710.000.", paket: 2 },
  { id: "pm54", subtes: "PM", topic: "Kecepatan Relatif", q: "Dua sepeda motor berangkat dari titik yang sama menuju arah yang sama. Motor pertama melaju 30 km/jam dan berangkat 20 menit lebih dulu dari motor kedua yang melaju 40 km/jam. Motor kedua akan menyusul motor pertama setelah motor kedua berjalan selama…", opts: ["45 menit", "1 jam", "1 jam 15 menit", "1 jam 30 menit"], answer: 1, pembahasan: "Jarak motor pertama saat motor kedua mulai = 30 × (20/60) = 10 km. Selisih kecepatan = 10 km/jam. Waktu menyusul = 10 ÷ 10 = 1 jam.", paket: 2 },
  { id: "pm55", subtes: "PM", topic: "Kebutuhan & Biaya Material", q: "Kebutuhan pupuk untuk suatu lahan adalah 25 kg per 100 m². Jika luas lahan yang akan dipupuk 350 m² dan harga pupuk Rp8.000/kg, total biaya pupuk yang dibutuhkan adalah…", opts: ["Rp600.000", "Rp650.000", "Rp700.000", "Rp750.000"], answer: 2, pembahasan: "Kebutuhan pupuk = 25/100 × 350 = 87,5 kg. Biaya = 87,5 × Rp8.000 = Rp700.000.", paket: 2 },

  // ---------- Literasi Bahasa Indonesia (LBI) ----------
  { id: "li1", subtes: "LBI", topic: "Makna Kata", q: "Kata 'kolaborasi' dalam sebuah teks tentang proyek bersama antarorganisasi paling tepat dimaknai sebagai…", opts: ["Persaingan", "Kerja sama untuk mencapai tujuan bersama", "Perselisihan", "Pengunduran diri"], answer: 1, pembahasan: "'Kolaborasi' dalam konteks proyek bersama berarti bekerja sama antarpihak demi tujuan bersama.", paket: 1 },
  { id: "li2", subtes: "LBI", topic: "Kalimat Efektif", q: "Manakah kalimat yang paling efektif dan baku?", opts: ["Dari hasil survey menunjukkan bahwa pelanggan merasa puas", "Hasil survei menunjukkan bahwa pelanggan merasa puas", "Survei tersebut hasilnya pelanggan puas menunjukkan", "Menunjukkan hasil survei pelanggan puas"], answer: 1, pembahasan: "Kata baku 'survei' (bukan 'survey') dan struktur kalimat aktif 'Hasil survei menunjukkan...' lebih efektif dan sesuai kaidah.", paket: 1 },
  { id: "li3", subtes: "LBI", topic: "Ide Pokok", q: "\"Pembelajaran daring semakin diminati oleh banyak institusi pendidikan karena fleksibilitas waktu, jangkauan yang luas, dan biaya operasional yang lebih efisien.\" Ide pokok kalimat tersebut adalah…", opts: ["Pembelajaran daring mahal", "Alasan pembelajaran daring semakin diminati", "Cara membuat pembelajaran daring", "Sejarah pembelajaran daring"], answer: 1, pembahasan: "Kalimat tersebut menjelaskan tiga alasan pembelajaran daring diminati — itulah gagasan utamanya.", paket: 1 },
  { id: "li4", subtes: "LBI", topic: "Kata Baku", q: "Bentuk kata baku yang tepat adalah…", opts: ["Kwalitas produk", "Kualitas produk", "Kwalitet produk", "Kualitet produk"], answer: 1, pembahasan: "Bentuk baku sesuai KBBI adalah 'kualitas', bukan 'kwalitas' atau 'kualitet'.", paket: 1 },
  { id: "li5", subtes: "LBI", topic: "Simpulan Paragraf", q: "\"Sampah plastik yang menumpuk di sungai menyebabkan aliran air tersumbat. Sumbatan ini mempercepat terjadinya banjir saat musim hujan.\" Simpulan yang tepat dari kedua kalimat tersebut adalah…", opts: ["Sampah plastik dapat mempercepat terjadinya banjir", "Banjir selalu terjadi walau sungai bersih", "Musim hujan tidak berkaitan dengan sungai", "Sampah plastik tidak memengaruhi aliran air"], answer: 0, pembahasan: "Kalimat kedua adalah akibat dari kalimat pertama (sampah menyumbat aliran → mempercepat banjir), sehingga simpulannya menggabungkan sebab-akibat itu.", paket: 1 },
  { id: "li6", subtes: "LBI", topic: "Konjungsi", q: "\"Kegiatan di luar ruangan ditunda ___ cuaca buruk memicu risiko keselamatan peserta.\" Konjungsi yang tepat untuk melengkapi kalimat tersebut adalah…", opts: ["dan", "karena", "meskipun", "atau"], answer: 1, pembahasan: "'Karena' tepat untuk menyatakan alasan/sebab ditundanya kegiatan.", paket: 1 },
  { id: "li7", subtes: "LBI", topic: "Makna Tersirat", q: "\"Meski anggaran terbatas, panitia tetap mengutamakan standar keamanan bagi seluruh peserta acara.\" Makna tersirat dari kalimat tersebut adalah…", opts: ["Anggaran tidak penting bagi panitia", "Standar keamanan bisa dikorbankan demi biaya", "Panitia tetap mengutamakan keamanan walau dana minim", "Acara tersebut dibatalkan"], answer: 2, pembahasan: "Kata 'meski/meskipun' menyiratkan pertentangan yang tetap dimenangkan sisi positif — panitia tetap mengutamakan keamanan walau dana terbatas.", paket: 1 },
  { id: "li8", subtes: "LBI", topic: "Ejaan", q: "Penulisan yang sesuai kaidah ejaan adalah…", opts: ["Kegiatan itu di kerjakan oleh panitia sekolah.", "Kegiatan itu dikerjakan oleh panitia sekolah.", "Kegiatan itu di-kerjakan oleh panitia sekolah.", "Kegiatan itu dikerja kan oleh panitia sekolah."], answer: 1, pembahasan: "Kata berimbuhan seperti 'dikerjakan' ditulis serangkai, bukan dipisah ('di kerjakan') atau diberi tanda hubung.", paket: 1 },
  { id: "li9", subtes: "LBI", topic: "Hubungan Antarkalimat", q: "\"Pemeriksaan kesehatan dilakukan untuk mengetahui kondisi tubuh pasien. Hasilnya menentukan jenis pengobatan yang diberikan.\" Hubungan antara kedua kalimat tersebut adalah…", opts: ["Pertentangan", "Sebab-akibat", "Perbandingan", "Penjelasan tidak berkaitan"], answer: 1, pembahasan: "Kalimat kedua menjelaskan akibat/kegunaan dari hasil kalimat pertama — hubungan sebab-akibat.", paket: 1 },
  { id: "li10", subtes: "LBI", topic: "Sinonim", q: "Sinonim kata 'inovasi' dalam konteks pengembangan produk adalah…", opts: ["Peniruan", "Pembaruan/gagasan baru", "Pengulangan", "Penghapusan"], answer: 1, pembahasan: "'Inovasi' bersinonim dengan 'pembaruan' atau 'gagasan baru' dalam konteks pengembangan produk.", paket: 1 },
  { id: "li11", subtes: "LBI", topic: "Kalimat Tidak Efektif", q: "Manakah kalimat yang TIDAK efektif?", opts: ["Panitia menyelesaikan acara tepat waktu.", "Acara tersebut diselesaikan tepat waktu oleh panitia.", "Acara itu punya panitia yang menyelesaikannya secara tepat pada waktunya.", "Panitia itu menyelesaikan acaranya dengan tepat waktu."], answer: 2, pembahasan: "Kalimat ketiga bertele-tele dan tidak langsung (boros kata) dibanding tiga kalimat lain yang lebih ringkas dan lugas.", paket: 1 },
  { id: "li12", subtes: "LBI", topic: "Ide Pokok", q: "\"Selain rasa, kandungan gizi juga menjadi pertimbangan utama dalam pemilihan bahan makanan untuk menu sehari-hari.\" Ide pokok paragraf tersebut adalah…", opts: ["Pertimbangan pemilihan bahan makanan", "Proses memasak makanan", "Harga bahan makanan", "Sejarah kuliner"], answer: 0, pembahasan: "Kalimat menjelaskan dua faktor (rasa dan gizi) yang dipertimbangkan dalam memilih bahan makanan — itulah gagasan utamanya.", paket: 1 },
  { id: "li13", subtes: "LBI", topic: "Antonim", q: "Antonim kata 'kokoh' dalam konteks daya tahan suatu benda adalah…", opts: ["Kuat", "Rapuh", "Tinggi", "Luas"], answer: 1, pembahasan: "Antonim 'kokoh' (kuat, tahan) adalah 'rapuh' (mudah rusak).", paket: 1 },
  { id: "li14", subtes: "LBI", topic: "Kata Baku", q: "Manakah pasangan kata yang sudah baku sesuai KBBI?", opts: ["Aktivitas – Sistim", "Aktifitas – Sistem", "Aktivitas – Sistem", "Aktifitas – Sistim"], answer: 2, pembahasan: "Bentuk baku sesuai KBBI adalah 'aktivitas' dan 'sistem', bukan 'aktifitas' atau 'sistim'.", paket: 1 },
  { id: "li15", subtes: "LBI", topic: "Simpulan Paragraf", q: "\"Servis rutin kendaraan mencegah kerusakan mesin yang lebih parah dan mahal untuk diperbaiki di kemudian hari.\" Simpulan yang paling tepat adalah…", opts: ["Servis rutin sebaiknya dihindari", "Servis rutin lebih hemat biaya jangka panjang", "Kerusakan mesin tidak bisa dicegah", "Biaya perbaikan selalu murah"], answer: 1, pembahasan: "Kalimat menunjukkan bahwa mencegah kerusakan besar lewat servis rutin lebih murah daripada memperbaikinya nanti — simpulannya soal penghematan jangka panjang.", paket: 1 },
  { id: "li16", subtes: "LBI", topic: "Kata Baku", q: "Bentuk kata baku yang tepat adalah…", opts: ["Aktivitas – Praktek", "Aktivitas – Praktik", "Aktifitas – Praktek", "Aktifitas – Praktik"], answer: 1, pembahasan: "Bentuk baku sesuai KBBI adalah 'aktivitas' dan 'praktik', bukan 'aktifitas' atau 'praktek'.", paket: 1 },
  { id: "li17", subtes: "LBI", topic: "Makna Kata", q: "Kata 'rehabilitasi' dalam konteks 'rehabilitasi taman kota' paling tepat dimaknai sebagai…", opts: ["Pembongkaran total", "Perbaikan untuk mengembalikan fungsi", "Pembangunan baru dari nol", "Penjualan aset"], answer: 1, pembahasan: "'Rehabilitasi' berarti memperbaiki sesuatu agar fungsinya kembali seperti semula, bukan membangun dari nol.", paket: 1 },
  { id: "li18", subtes: "LBI", topic: "Konjungsi", q: "\"Kegiatan di lapangan dihentikan sementara ___ ditemukan tanda-tanda cuaca ekstrem akan datang.\" Konjungsi yang tepat adalah…", opts: ["meskipun", "karena", "atau", "kemudian"], answer: 1, pembahasan: "'Karena' tepat menyatakan alasan kegiatan dihentikan (ditemukannya tanda cuaca ekstrem).", paket: 1 },
  { id: "li19", subtes: "LBI", topic: "Ide Pokok", q: "\"Manajemen keuangan pribadi mencakup pencatatan pengeluaran, penyusunan anggaran, dan penyisihan dana darurat sebelum mulai berinvestasi.\" Ide pokok kalimat tersebut adalah…", opts: ["Tahapan manajemen keuangan pribadi", "Sejarah investasi", "Biaya investasi", "Jenis-jenis instrumen investasi"], answer: 0, pembahasan: "Kalimat menyebutkan tiga tahapan manajemen keuangan pribadi — itulah gagasan utamanya.", paket: 1 },
  { id: "li20", subtes: "LBI", topic: "Kalimat Efektif", q: "Manakah kalimat yang paling efektif?", opts: ["Dikarenakan karena hujan deras, pertandingan ditunda.", "Karena hujan deras, pertandingan ditunda.", "Hujan deras dikarenakan, pertandingan ditunda.", "Ditunda pertandingan karena dikarenakan hujan deras."], answer: 1, pembahasan: "'Dikarenakan' dan 'karena' tidak boleh dipakai bersamaan; cukup gunakan salah satu, di sini 'karena' yang tepat.", paket: 1 },
  { id: "li21", subtes: "LBI", topic: "Antonim", q: "Antonim kata 'efisien' dalam konteks penggunaan waktu adalah…", opts: ["Hemat", "Boros", "Cepat", "Ringkas"], answer: 1, pembahasan: "Antonim 'efisien' (hemat, tepat guna) adalah 'boros'.", paket: 1 },
  { id: "li22", subtes: "LBI", topic: "Sinonim", q: "Sinonim kata 'durabilitas' dalam konteks produk elektronik adalah…", opts: ["Keindahan", "Daya tahan", "Kecepatan pengiriman", "Harga"], answer: 1, pembahasan: "'Durabilitas' bersinonim dengan 'daya tahan' suatu produk.", paket: 1 },
  { id: "li23", subtes: "LBI", topic: "Ejaan", q: "Penulisan kata yang sesuai kaidah ejaan adalah…", opts: ["Non-formal", "Nonformal", "Non formal", "Nonformal-al"], answer: 1, pembahasan: "Prefiks 'non-' digabung tanpa tanda hubung dengan kata dasar: 'nonformal'.", paket: 1 },
  { id: "li24", subtes: "LBI", topic: "Simpulan Paragraf", q: "\"Penggunaan aplikasi manajemen tugas memungkinkan anggota tim memantau progres pekerjaan secara real-time, sehingga mengurangi miskomunikasi antaranggota.\" Simpulan yang tepat adalah…", opts: ["Aplikasi ini hanya berguna untuk manajer", "Aplikasi ini membantu mengurangi miskomunikasi lewat pemantauan progres", "Aplikasi ini menggantikan seluruh pekerjaan tim", "Aplikasi ini tidak berkaitan dengan progres kerja"], answer: 1, pembahasan: "Kalimat menjelaskan manfaat aplikasi (memantau progres, mengurangi miskomunikasi) — itulah simpulan yang didukung teks.", paket: 1 },
  { id: "li25", subtes: "LBI", topic: "Makna Tersirat", q: "\"Walaupun jadwal produksi sudah sangat ketat, tim kendali mutu tetap menahan pengiriman produk karena hasil uji tidak memenuhi syarat.\" Makna tersirat dari kalimat tersebut adalah…", opts: ["Jadwal produksi lebih penting daripada mutu", "Tim kendali mutu mengutamakan mutu meski berisiko terlambat", "Hasil uji tidak memengaruhi keputusan pengiriman", "Pengiriman produk tetap dilanjutkan tanpa syarat"], answer: 1, pembahasan: "Kata 'walaupun' menunjukkan sikap tim tetap mengutamakan mutu meski berisiko molor dari jadwal.", paket: 1 },
  { id: "li26", subtes: "LBI", topic: "Makna Kata", q: "Kata 'transparansi' dalam konteks pengelolaan dana organisasi paling tepat dimaknai sebagai…", opts: ["Kerahasiaan penuh", "Keterbukaan informasi kepada publik", "Pembatasan akses informasi", "Penundaan laporan"], answer: 1, pembahasan: "'Transparansi' berarti keterbukaan, terutama dalam menyampaikan informasi (misalnya pengelolaan dana) kepada pihak yang berkepentingan.", paket: 1 },
  { id: "li27", subtes: "LBI", topic: "Kalimat Baku", q: "Manakah kalimat yang menggunakan ejaan dan tanda baca baku?", opts: ["Rapat akan dimulai pukul 09.00 WIB.", "Rapat akan dimulai pukul 09:00 wib.", "Rapat akan dimulai pukul 09.00 W I B.", "Rapat akan di mulai pukul 09.00 WIB."], answer: 0, pembahasan: "Penulisan waktu baku memakai tanda titik (09.00) dan singkatan WIB huruf kapital tanpa spasi, serta 'dimulai' ditulis serangkai.", paket: 1 },
  { id: "li28", subtes: "LBI", topic: "Ide Pokok", q: "\"Literasi digital penting dikuasai generasi muda agar mampu memilah informasi yang benar di tengah derasnya arus berita di internet.\" Ide pokok kalimat tersebut adalah…", opts: ["Pentingnya literasi digital bagi generasi muda", "Sejarah perkembangan internet", "Cara membuat berita", "Jumlah pengguna internet di Indonesia"], answer: 0, pembahasan: "Kalimat menjelaskan alasan literasi digital penting bagi generasi muda — itulah gagasan utamanya.", paket: 1 },
  { id: "li29", subtes: "LBI", topic: "Antonim", q: "Antonim kata 'transparan' dalam konteks pengelolaan informasi adalah…", opts: ["Terbuka", "Tertutup", "Jelas", "Jujur"], answer: 1, pembahasan: "Antonim 'transparan' (terbuka) adalah 'tertutup'.", paket: 1 },
  { id: "li30", subtes: "LBI", topic: "Simpulan Paragraf", q: "\"Membiasakan menabung sejak dini membantu seseorang lebih siap menghadapi kebutuhan mendesak di masa depan.\" Simpulan yang tepat adalah…", opts: ["Menabung sejak dini bermanfaat untuk kesiapan finansial di masa depan", "Menabung hanya perlu dilakukan saat dewasa", "Kebutuhan mendesak tidak bisa diprediksi sama sekali", "Menabung tidak memengaruhi kesiapan finansial"], answer: 0, pembahasan: "Kalimat menunjukkan manfaat menabung sejak dini terhadap kesiapan finansial di masa depan — itu simpulannya.", paket: 1 },
  { id: "li31", subtes: "LBI", topic: "Makna Kata", q: "Kata 'restorasi' dalam konteks 'restorasi bangunan bersejarah' paling tepat dimaknai sebagai…", opts: ["Pembongkaran total", "Pemugaran untuk mengembalikan kondisi asli", "Pembangunan gedung baru", "Penjualan aset bersejarah"], answer: 1, pembahasan: "'Restorasi' berarti pemugaran atau perbaikan untuk mengembalikan sesuatu ke kondisi/bentuk aslinya.", paket: 2 },
  { id: "li32", subtes: "LBI", topic: "Kalimat Efektif", q: "Manakah kalimat yang paling efektif dan baku?", opts: ["Berdasarkan data menunjukkan bahwa angka melek huruf meningkat.", "Data menunjukkan bahwa angka melek huruf meningkat.", "Data, angka melek huruf meningkat menunjukkan.", "Menunjukkan data angka melek huruf meningkat."], answer: 1, pembahasan: "Penggunaan 'berdasarkan data menunjukkan' rancu karena menggabungkan dua struktur kalimat; cukup gunakan 'data menunjukkan'.", paket: 2 },
  { id: "li33", subtes: "LBI", topic: "Ide Pokok", q: "\"Program vaksinasi massal membantu menekan penyebaran penyakit menular sekaligus melindungi kelompok rentan di masyarakat.\" Ide pokok kalimat tersebut adalah…", opts: ["Kerugian program vaksinasi", "Manfaat program vaksinasi massal", "Cara membuat vaksin", "Sejarah vaksinasi"], answer: 1, pembahasan: "Kalimat menjelaskan manfaat program vaksinasi massal — itulah gagasan utamanya.", paket: 2 },
  { id: "li34", subtes: "LBI", topic: "Kata Baku", q: "Bentuk kata baku yang tepat adalah…", opts: ["Apotik – Ijazah", "Apotek – Ijazah", "Apotik – Ijasah", "Apotek – Ijasah"], answer: 1, pembahasan: "Bentuk baku sesuai KBBI adalah 'apotek' dan 'ijazah'.", paket: 2 },
  { id: "li35", subtes: "LBI", topic: "Simpulan Paragraf", q: "\"Sampah organik yang dipilah dapat diolah menjadi kompos yang menyuburkan tanah.\" Simpulan yang tepat dari kalimat tersebut adalah…", opts: ["Sampah organik yang dipilah bermanfaat menjadi kompos", "Semua sampah harus dibakar", "Kompos tidak berkaitan dengan sampah organik", "Tanah tidak membutuhkan kompos"], answer: 0, pembahasan: "Kalimat menunjukkan manfaat pemilahan sampah organik menjadi kompos — itu simpulannya.", paket: 2 },
  { id: "li36", subtes: "LBI", topic: "Konjungsi", q: "\"Jadwal keberangkatan kereta ditunda ___ terjadi gangguan teknis pada rel.\" Konjungsi yang tepat untuk melengkapi kalimat tersebut adalah…", opts: ["dan", "karena", "meskipun", "atau"], answer: 1, pembahasan: "'Karena' tepat untuk menyatakan alasan/sebab tertundanya jadwal keberangkatan.", paket: 2 },
  { id: "li37", subtes: "LBI", topic: "Makna Tersirat", q: "\"Meski jadwal ujian dimajukan, sebagian besar siswa tetap tenang karena telah belajar sejak jauh hari.\" Makna tersirat dari kalimat tersebut adalah…", opts: ["Siswa tidak siap menghadapi ujian", "Persiapan sejak dini membuat siswa lebih siap menghadapi perubahan jadwal", "Ujian pasti ditunda kembali", "Belajar sejak jauh hari tidak berpengaruh"], answer: 1, pembahasan: "Kalimat menyiratkan bahwa persiapan sejak dini membuat siswa tetap tenang meski jadwal ujian berubah.", paket: 2 },
  { id: "li38", subtes: "LBI", topic: "Ejaan", q: "Penulisan yang sesuai kaidah ejaan adalah…", opts: ["Buku itu di terbitkan tahun lalu.", "Buku itu diterbitkan tahun lalu.", "Buku itu di-terbitkan tahun lalu.", "Buku itu diterbit kan tahun lalu."], answer: 1, pembahasan: "Kata berimbuhan seperti 'diterbitkan' ditulis serangkai, bukan dipisah atau diberi tanda hubung.", paket: 2 },
  { id: "li39", subtes: "LBI", topic: "Hubungan Antarkalimat", q: "\"Guru memberikan kuis dadakan di awal pelajaran. Kuis ini mendorong siswa untuk selalu membaca materi sebelum kelas dimulai.\" Hubungan antara kedua kalimat tersebut adalah…", opts: ["Pertentangan", "Sebab-akibat", "Perbandingan", "Penjelasan tidak berkaitan"], answer: 1, pembahasan: "Kalimat kedua menjelaskan akibat/dampak dari tindakan di kalimat pertama — hubungan sebab-akibat.", paket: 2 },
  { id: "li40", subtes: "LBI", topic: "Sinonim", q: "Sinonim kata 'signifikan' dalam konteks hasil penelitian adalah…", opts: ["Sepele", "Berarti/penting", "Meragukan", "Kebetulan"], answer: 1, pembahasan: "'Signifikan' bersinonim dengan 'berarti' atau 'penting', menunjukkan sesuatu yang bermakna secara statistik/substansial.", paket: 2 },
  { id: "li41", subtes: "LBI", topic: "Kalimat Tidak Efektif", q: "Manakah kalimat yang TIDAK efektif?", opts: ["Pemerintah menetapkan kebijakan baru.", "Kebijakan baru ditetapkan oleh pemerintah.", "Kebijakan baru itu, pemerintah yang menetapkannya secara resmi.", "Pemerintah secara resmi menetapkan kebijakan baru itu."], answer: 2, pembahasan: "Kalimat ketiga bertele-tele dan strukturnya tidak lugas dibanding tiga kalimat lain yang lebih ringkas.", paket: 2 },
  { id: "li42", subtes: "LBI", topic: "Ide Pokok", q: "\"Selain rasanya yang gurih, kandungan protein dalam tempe menjadikannya sumber gizi yang terjangkau bagi masyarakat.\" Ide pokok paragraf tersebut adalah…", opts: ["Keunggulan tempe sebagai sumber gizi terjangkau", "Cara membuat tempe", "Harga bahan baku tempe", "Sejarah tempe di Indonesia"], answer: 0, pembahasan: "Kalimat menjelaskan keunggulan tempe (rasa dan gizi) sebagai sumber gizi terjangkau — itu gagasan utamanya.", paket: 2 },
  { id: "li43", subtes: "LBI", topic: "Antonim", q: "Antonim kata 'optimis' dalam konteks menghadapi tantangan adalah…", opts: ["Yakin", "Pesimis", "Percaya diri", "Berani"], answer: 1, pembahasan: "Antonim 'optimis' (yakin akan hasil baik) adalah 'pesimis'.", paket: 2 },
  { id: "li44", subtes: "LBI", topic: "Kata Baku", q: "Manakah pasangan kata yang sudah baku sesuai KBBI?", opts: ["Nasihat – Karier", "Nasehat – Karir", "Nasihat – Karir", "Nasehat – Karier"], answer: 0, pembahasan: "Bentuk baku sesuai KBBI adalah 'nasihat' dan 'karier'.", paket: 2 },
  { id: "li45", subtes: "LBI", topic: "Simpulan Paragraf", q: "\"Penerapan kurikulum berbasis proyek mendorong siswa berpikir kritis dan bekerja sama menyelesaikan masalah nyata.\" Simpulan yang paling tepat adalah…", opts: ["Kurikulum berbasis proyek melatih keterampilan berpikir kritis dan kerja sama siswa", "Kurikulum berbasis proyek tidak efektif", "Siswa tidak perlu bekerja sama", "Masalah nyata tidak relevan dengan pembelajaran"], answer: 0, pembahasan: "Kalimat menunjukkan manfaat kurikulum berbasis proyek terhadap keterampilan berpikir kritis dan kerja sama siswa.", paket: 2 },
  { id: "li46", subtes: "LBI", topic: "Makna Kata", q: "Kata 'advokasi' dalam konteks 'advokasi hak-hak petani' paling tepat dimaknai sebagai…", opts: ["Penolakan terhadap suatu hal", "Pembelaan atau dukungan aktif terhadap suatu hal", "Penghapusan hak seseorang", "Penundaan suatu keputusan"], answer: 1, pembahasan: "'Advokasi' berarti tindakan membela atau mendukung secara aktif suatu isu atau kelompok, seperti hak-hak petani.", paket: 2 },
  { id: "li47", subtes: "LBI", topic: "Konjungsi", q: "\"Penelitian ini masih perlu diuji lebih lanjut ___ hasilnya cukup menjanjikan.\" Konjungsi yang tepat adalah…", opts: ["karena", "meskipun", "sehingga", "atau"], answer: 1, pembahasan: "'Meskipun' tepat menyatakan pertentangan antara hasil yang menjanjikan dengan kebutuhan pengujian lebih lanjut.", paket: 2 },
  { id: "li48", subtes: "LBI", topic: "Ejaan", q: "Penulisan kata yang sesuai kaidah ejaan adalah…", opts: ["Antar-kota", "Antarkota", "Antar kota", "Antarkota-kota"], answer: 1, pembahasan: "Prefiks 'antar-' digabung tanpa tanda hubung dengan kata dasar: 'antarkota'.", paket: 2 },
  { id: "li49", subtes: "LBI", topic: "Hubungan Antarkalimat", q: "\"Petani menerapkan sistem irigasi tetes pada lahannya. Sistem ini menghemat penggunaan air secara signifikan.\" Hubungan antara kedua kalimat tersebut adalah…", opts: ["Pertentangan", "Sebab-akibat", "Perbandingan", "Tidak berkaitan"], answer: 1, pembahasan: "Kalimat kedua menjelaskan akibat/manfaat dari penerapan sistem irigasi tetes — hubungan sebab-akibat.", paket: 2 },
  { id: "li50", subtes: "LBI", topic: "Sinonim", q: "Sinonim kata 'kolaboratif' dalam konteks kerja tim adalah…", opts: ["Kompetitif", "Kooperatif", "Individual", "Pasif"], answer: 1, pembahasan: "'Kolaboratif' bersinonim dengan 'kooperatif', yaitu bersifat bekerja sama.", paket: 2 },
  { id: "li51", subtes: "LBI", topic: "Kalimat Efektif", q: "Manakah kalimat yang paling efektif?", opts: ["Agar supaya lulus ujian, siswa harus rajin belajar.", "Agar lulus ujian, siswa harus rajin belajar.", "Supaya agar lulus ujian, siswa harus rajin belajar.", "Untuk agar lulus ujian, siswa harus rajin belajar."], answer: 1, pembahasan: "Kata 'agar' dan 'supaya' memiliki makna yang sama, sehingga tidak boleh dipakai bersamaan dalam satu kalimat.", paket: 2 },
  { id: "li52", subtes: "LBI", topic: "Antonim", q: "Antonim kata 'fleksibel' dalam konteks jadwal kerja adalah…", opts: ["Luwes", "Kaku", "Mudah", "Bebas"], answer: 1, pembahasan: "Antonim 'fleksibel' (luwes, mudah menyesuaikan) adalah 'kaku'.", paket: 2 },
  { id: "li53", subtes: "LBI", topic: "Ide Pokok", q: "\"Digitalisasi arsip mempermudah pencarian dokumen dan mengurangi risiko kerusakan fisik akibat waktu.\" Ide pokok kalimat tersebut adalah…", opts: ["Kerugian digitalisasi arsip", "Manfaat digitalisasi arsip", "Sejarah kearsipan", "Biaya digitalisasi"], answer: 1, pembahasan: "Kalimat menjelaskan dua manfaat digitalisasi arsip — itulah gagasan utamanya.", paket: 2 },
  { id: "li54", subtes: "LBI", topic: "Kata Baku", q: "Bentuk kata baku yang tepat adalah…", opts: ["Frekwensi – Metode", "Frekuensi – Metode", "Frekwensi – Metoda", "Frekuensi – Metoda"], answer: 1, pembahasan: "Bentuk baku sesuai KBBI adalah 'frekuensi' dan 'metode'.", paket: 2 },
  { id: "li55", subtes: "LBI", topic: "Simpulan Paragraf", q: "\"Diversifikasi tanaman pangan mengurangi ketergantungan petani pada satu jenis komoditas saja.\" Simpulan yang tepat adalah…", opts: ["Diversifikasi tanaman membantu petani mengurangi risiko ketergantungan komoditas", "Petani sebaiknya hanya menanam satu jenis tanaman", "Diversifikasi tidak berkaitan dengan risiko", "Komoditas tunggal lebih menguntungkan"], answer: 0, pembahasan: "Kalimat menunjukkan manfaat diversifikasi tanaman dalam mengurangi ketergantungan pada satu komoditas — itu simpulannya.", paket: 2 },
  { id: "li56", subtes: "LBI", topic: "Makna Tersirat", q: "\"Walaupun anggaran riset terbatas, tim peneliti tetap berhasil mempublikasikan temuan pentingnya di jurnal internasional.\" Makna tersirat dari kalimat tersebut adalah…", opts: ["Anggaran besar adalah syarat mutlak keberhasilan riset", "Keterbatasan anggaran tidak menghalangi pencapaian signifikan jika diusahakan", "Tim peneliti gagal mempublikasikan temuannya", "Jurnal internasional tidak menerima riset beranggaran kecil"], answer: 1, pembahasan: "Kata 'walaupun' menyiratkan bahwa keterbatasan anggaran tidak menghalangi tim mencapai hasil signifikan.", paket: 2 },
  { id: "li57", subtes: "LBI", topic: "Konjungsi", q: "\"Harga bahan pangan cenderung naik ___ mendekati hari raya.\" Konjungsi yang tepat adalah…", opts: ["ketika", "meskipun", "walaupun", "andaikan"], answer: 0, pembahasan: "'Ketika' tepat menyatakan hubungan waktu antara kenaikan harga dan mendekati hari raya.", paket: 2 },
  { id: "li58", subtes: "LBI", topic: "Hubungan Antarkalimat", q: "\"Tim redaksi memverifikasi setiap berita sebelum diterbitkan. Langkah ini mencegah penyebaran informasi yang keliru.\" Hubungan antara kedua kalimat tersebut adalah…", opts: ["Pertentangan", "Tujuan-akibat", "Perbandingan", "Tidak berkaitan"], answer: 1, pembahasan: "Kalimat kedua menjelaskan tujuan/manfaat dari tindakan verifikasi di kalimat pertama — hubungan tujuan-akibat.", paket: 2 },
  { id: "li59", subtes: "LBI", topic: "Sinonim", q: "Sinonim kata 'esensial' dalam konteks kebutuhan pokok adalah…", opts: ["Tambahan", "Mendasar/penting", "Mewah", "Opsional"], answer: 1, pembahasan: "'Esensial' bersinonim dengan 'mendasar' atau 'penting', menunjukkan sesuatu yang sangat diperlukan.", paket: 2 },
  { id: "li60", subtes: "LBI", topic: "Ejaan", q: "Penulisan kata yang sesuai kaidah ejaan adalah…", opts: ["Se-Indonesia", "SeIndonesia", "Se Indonesia", "se-indonesia"], answer: 0, pembahasan: "Prefiks 'se-' yang diikuti kata berawalan huruf kapital ditulis dengan tanda hubung: 'Se-Indonesia'.", paket: 2 },

  // ---------- Literasi Bahasa Inggris (LBE) ----------
  { id: "le1", subtes: "LBE", topic: "Grammar", q: "Choose the correct sentence:", opts: ["The library were built in 1998.", "The library was built in 1998.", "The library building in 1998.", "The library has build in 1998."], answer: 1, pembahasan: "Subjek tunggal 'The library' memakai 'was' (bentuk lampau tunggal), bukan 'were'.", paket: 1 },
  { id: "le2", subtes: "LBE", topic: "Vocabulary", q: "\"The product's durability depends heavily on the quality of its materials.\" The word 'durability' is closest in meaning to:", opts: ["Beauty", "Cost", "Ability to last", "Weight"], answer: 2, pembahasan: "'Durability' berarti kemampuan untuk bertahan lama (ability to last).", paket: 1 },
  { id: "le3", subtes: "LBE", topic: "Reading Comprehension", q: "\"Effective teamwork combines the individual strengths of each member with clear communication among the group.\" This sentence mainly explains…", opts: ["Why teamwork is expensive", "How effective teamwork works", "The history of teamwork", "How to avoid teamwork"], answer: 1, pembahasan: "Kalimat menjelaskan bagaimana kerja sama tim yang efektif berjalan — itu inti bacaannya.", paket: 1 },
  { id: "le4", subtes: "LBE", topic: "Grammar", q: "\"The students ___ finished the assignment before the deadline arrived.\" Choose the correct verb form:", opts: ["have", "has", "had", "having"], answer: 2, pembahasan: "Klausa waktu lampau ('before the deadline arrived') memakai past perfect 'had finished' untuk kejadian yang terjadi lebih dulu.", paket: 1 },
  { id: "le5", subtes: "LBE", topic: "Vocabulary", q: "In everyday context, the word 'reliable' most closely means…", opts: ["Decorative", "Able to be trusted", "Waterproof", "Temporary"], answer: 1, pembahasan: "'Reliable' berarti dapat dipercaya/diandalkan (able to be trusted).", paket: 1 },
  { id: "le6", subtes: "LBE", topic: "Grammar", q: "\"Teachers ___ the students' essays before returning them.\" Choose the correct verb form to agree with the plural subject:", opts: ["is reviewed", "reviewing", "review", "are review"], answer: 2, pembahasan: "Subjek jamak 'Teachers' dengan simple present memakai bentuk dasar 'review' tanpa akhiran -s.", paket: 1 },
  { id: "le7", subtes: "LBE", topic: "Reading Comprehension", q: "\"Market research is conducted before launching a product to understand customer needs and preferences.\" Why is market research conducted?", opts: ["To decorate the office", "To understand customer needs and preferences", "To measure rainfall", "To hire workers"], answer: 1, pembahasan: "Kalimat menyatakan riset pasar dilakukan untuk memahami kebutuhan dan preferensi pelanggan — itu tujuannya.", paket: 1 },
  { id: "le8", subtes: "LBE", topic: "Vocabulary", q: "The word 'sustainable' in \"sustainable packaging\" is closest in meaning to…", opts: ["Expensive", "Environmentally friendly and long-lasting", "Colorful", "Imported"], answer: 1, pembahasan: "'Sustainable' berarti ramah lingkungan dan tahan lama (environmentally friendly and long-lasting).", paket: 1 },
  { id: "le9", subtes: "LBE", topic: "Grammar", q: "\"If the fruit ___ properly stored, it will not stay fresh.\" Choose the correct conditional form:", opts: ["is not", "was not", "were not", "will not"], answer: 0, pembahasan: "Present tense 'is not' dipakai pada zero conditional/first conditional untuk syarat yang berlaku umum.", paket: 1 },
  { id: "le10", subtes: "LBE", topic: "Reading Comprehension", q: "\"Despite the tight deadline, the team prioritized quality checks at every stage.\" What does this sentence imply?", opts: ["Quality was ignored due to time pressure", "Quality remained a priority despite time pressure", "The deadline was extended", "Checks were cancelled"], answer: 1, pembahasan: "'Despite' menunjukkan kualitas tetap diutamakan meskipun ada tekanan waktu.", paket: 1 },
  { id: "le11", subtes: "LBE", topic: "Vocabulary", q: "The term 'outline' in a writing context refers to…", opts: ["A type of paint", "A structured plan or summary of key points", "A safety helmet", "A construction worker"], answer: 1, pembahasan: "'Outline' berarti rencana atau ringkasan terstruktur dari poin-poin utama.", paket: 1 },
  { id: "le12", subtes: "LBE", topic: "Grammar", q: "Choose the correct sentence:", opts: ["The students has completed the project.", "The students have completed the project.", "The students completing the project.", "The students is completed the project."], answer: 1, pembahasan: "Subjek jamak 'The students' memakai 'have' (bukan 'has') pada present perfect.", paket: 1 },
  { id: "le13", subtes: "LBE", topic: "Reading Comprehension", q: "\"Although the initial cost of electric cars is higher, their lower maintenance cost often makes them more economical over time.\" This sentence is mainly about…", opts: ["Electric cars are always more expensive", "The long-term economic benefit of electric cars", "How to build electric cars", "Electric cars are unsafe"], answer: 1, pembahasan: "Kalimat membandingkan biaya awal vs biaya jangka panjang mobil listrik — intinya keuntungan ekonomis jangka panjang.", paket: 1 },
  { id: "le14", subtes: "LBE", topic: "Vocabulary", q: "The word 'feasibility' in 'feasibility study' means…", opts: ["The cost of a project", "The possibility of a plan being successfully carried out", "The location of a project", "The team assigned to a project"], answer: 1, pembahasan: "'Feasibility' berarti kemungkinan suatu rencana dapat berhasil dilaksanakan.", paket: 1 },
  { id: "le15", subtes: "LBE", topic: "Grammar", q: "\"By the time the manager arrives, the team ___ the report.\" Choose the correct form:", opts: ["will have finished", "will finish", "finishes", "finishing"], answer: 0, pembahasan: "Future perfect 'will have finished' dipakai untuk kejadian yang akan selesai sebelum waktu tertentu di masa depan.", paket: 1 },
  { id: "le16", subtes: "LBE", topic: "Grammar", q: "Choose the correct sentence:", opts: ["The research team have finish the data collection.", "The research team has finished the data collection.", "The research team finishing the data collection.", "The research team is finish the data collection."], answer: 1, pembahasan: "Subjek tunggal 'The research team' memakai 'has finished' (bukan 'have finish').", paket: 1 },
  { id: "le17", subtes: "LBE", topic: "Vocabulary", q: "In project management, the word 'contingency' (as in 'contingency budget') most closely means…", opts: ["Extra funds reserved for unexpected costs", "The main construction cost", "Salary of workers", "The final project report"], answer: 0, pembahasan: "'Contingency' (dalam 'contingency budget') berarti dana cadangan untuk biaya tak terduga.", paket: 1 },
  { id: "le18", subtes: "LBE", topic: "Reading Comprehension", q: "\"Food safety inspectors check product samples at every stage to ensure compliance with health regulations.\" What is the main purpose of food safety inspectors mentioned in this sentence?", opts: ["To manage the company budget", "To ensure products meet health regulations", "To hire new staff", "To design packaging"], answer: 1, pembahasan: "Kalimat menyatakan inspektur keamanan pangan memeriksa produk agar sesuai regulasi kesehatan — itu tujuan utamanya.", paket: 1 },
  { id: "le19", subtes: "LBE", topic: "Grammar", q: "\"The report ___ before the meeting started.\" Choose the correct form:", opts: ["was completed", "completed", "completing", "has complete"], answer: 0, pembahasan: "Kejadian yang selesai sebelum kejadian lampau lain memakai past simple pasif 'was completed'.", paket: 1 },
  { id: "le20", subtes: "LBE", topic: "Vocabulary", q: "The word 'analysis' in an academic context refers to…", opts: ["The detailed examination of something's elements", "A type of decoration", "A safety procedure", "A financial report"], answer: 0, pembahasan: "'Analysis' berarti pemeriksaan mendetail terhadap unsur-unsur suatu hal.", paket: 1 },
  { id: "le21", subtes: "LBE", topic: "Grammar", q: "Choose the correct sentence using the passive voice:", opts: ["The annual report was reviewed by the board of directors.", "The annual report reviewed by the board of directors.", "The board of directors reviewing the annual report.", "The annual report review by the board of directors."], answer: 0, pembahasan: "Kalimat pasif dibentuk dari objek + 'was/were' + past participle + 'by' + pelaku: 'was reviewed by...'." },
  { id: "le22", subtes: "LBE", topic: "Reading Comprehension", q: "\"Although the project was originally scheduled for completion in six months, unexpected budget issues extended the timeline by two months.\" How long did the project actually take?", opts: ["Six months", "Four months", "Eight months", "Two months"], answer: 2, pembahasan: "Jadwal awal 6 bulan + keterlambatan 2 bulan = proyek selesai dalam 8 bulan." },
  { id: "le23", subtes: "LBE", topic: "Vocabulary", q: "The term 'data integrity' most closely means…", opts: ["The accuracy and consistency of data over its lifecycle", "The appearance of a database", "The cost of storing data", "The speed of data transfer"], answer: 0, pembahasan: "'Data integrity' berarti keakuratan dan konsistensi data sepanjang siklus penggunaannya." },
  { id: "le24", subtes: "LBE", topic: "Grammar", q: "\"By next month, the company ___ the entire renovation project.\" Choose the correct future perfect form:", opts: ["will complete", "will have completed", "completes", "is completing"], answer: 1, pembahasan: "Future perfect 'will have completed' dipakai untuk kejadian yang akan selesai sebelum waktu tertentu di masa depan." },
  { id: "le25", subtes: "LBE", topic: "Reading Comprehension", q: "\"Regular exercise is essential because inadequate physical activity can lead to health problems over time.\" Why is regular exercise important according to the passage?", opts: ["It makes people busier", "It prevents health problems from inactivity", "It reduces medical costs directly", "It improves appearance only"], answer: 1, pembahasan: "Kalimat menyatakan olahraga teratur mencegah masalah kesehatan akibat kurang gerak — itu jawabannya." },
  { id: "le26", subtes: "LBE", topic: "Grammar", q: "Choose the correct sentence:", opts: ["The museum were renovated last year.", "The museum was renovated last year.", "The museum renovating last year.", "The museum has renovate last year."], answer: 1, pembahasan: "Subjek tunggal 'The museum' memakai 'was' (bentuk lampau tunggal), bukan 'were'.", paket: 2 },
  { id: "le27", subtes: "LBE", topic: "Vocabulary", q: "\"The committee's decision was based on comprehensive research.\" The word 'comprehensive' is closest in meaning to:", opts: ["Brief", "Thorough", "Biased", "Delayed"], answer: 1, pembahasan: "'Comprehensive' berarti menyeluruh/lengkap (thorough).", paket: 2 },
  { id: "le28", subtes: "LBE", topic: "Reading Comprehension", q: "\"Renewable energy sources, such as solar and wind, produce far less pollution than fossil fuels.\" This sentence mainly compares…", opts: ["The cost of solar and wind energy", "The pollution levels of renewable energy and fossil fuels", "The history of energy production", "The efficiency of wind turbines"], answer: 1, pembahasan: "Kalimat membandingkan tingkat polusi antara energi terbarukan dan bahan bakar fosil.", paket: 2 },
  { id: "le29", subtes: "LBE", topic: "Grammar", q: "\"By the time she ___ home, the meeting had already ended.\" Choose the correct form:", opts: ["arrives", "arrived", "had arrived", "was arriving"], answer: 1, pembahasan: "Kejadian lampau tunggal ('arrived') digunakan bersama past perfect ('had ended') untuk menunjukkan urutan dua kejadian di masa lalu.", paket: 2 },
  { id: "le30", subtes: "LBE", topic: "Vocabulary", q: "The word 'accessible' in \"accessible public facilities\" is closest in meaning to…", opts: ["Expensive", "Easy to reach or use", "Hidden", "Temporary"], answer: 1, pembahasan: "'Accessible' berarti mudah dijangkau atau digunakan (easy to reach or use).", paket: 2 },
  { id: "le31", subtes: "LBE", topic: "Grammar", q: "\"Neither the manager nor the employees ___ aware of the change.\" Choose the correct verb form:", opts: ["was", "were", "is", "has been"], answer: 1, pembahasan: "Pada konstruksi 'neither...nor', kata kerja mengikuti subjek terdekat (the employees, jamak), sehingga memakai 'were'.", paket: 2 },
  { id: "le32", subtes: "LBE", topic: "Reading Comprehension", q: "\"Despite initial skepticism, the new policy gradually gained public support after its benefits became evident.\" What does this sentence imply?", opts: ["The policy was rejected permanently", "Public opinion shifted positively over time", "The policy had no benefits", "Skepticism increased over time"], answer: 1, pembahasan: "Kalimat menyiratkan bahwa opini publik berubah menjadi positif seiring waktu setelah manfaat kebijakan terlihat.", paket: 2 },
  { id: "le33", subtes: "LBE", topic: "Vocabulary", q: "The term 'preliminary' in \"preliminary results\" most closely means…", opts: ["Final", "Initial/early", "Incorrect", "Detailed"], answer: 1, pembahasan: "'Preliminary' berarti awal/pendahuluan (initial/early), sebelum hasil akhir diperoleh.", paket: 2 },
  { id: "le34", subtes: "LBE", topic: "Grammar", q: "Choose the correct passive form: \"The new policy ___ next month.\"", opts: ["will implement", "will be implemented", "is implementing", "implements"], answer: 1, pembahasan: "Bentuk pasif future tense: 'will be' + past participle, sehingga 'will be implemented'.", paket: 2 },
  { id: "le35", subtes: "LBE", topic: "Reading Comprehension", q: "\"Although remote work offers flexibility, many employees report feeling isolated without regular face-to-face interaction.\" What is the main concern mentioned in this sentence?", opts: ["Remote work is too flexible", "Employees feel isolated due to lack of in-person interaction", "Employees prefer remote work entirely", "Face-to-face interaction is unnecessary"], answer: 1, pembahasan: "Kalimat menyebutkan kekhawatiran utama, yaitu rasa terisolasi karyawan akibat kurangnya interaksi tatap muka.", paket: 2 },
  { id: "le36", subtes: "LBE", topic: "Vocabulary", q: "The word 'inevitable' in \"an inevitable outcome\" is closest in meaning to…", opts: ["Avoidable", "Certain to happen", "Surprising", "Temporary"], answer: 1, pembahasan: "'Inevitable' berarti pasti terjadi (certain to happen), tidak dapat dihindari.", paket: 2 },
  { id: "le37", subtes: "LBE", topic: "Grammar", q: "\"If I ___ more time, I would have finished the report.\" Choose the correct conditional form:", opts: ["have", "had", "had had", "will have"], answer: 2, pembahasan: "Pengandaian tipe ketiga (hal yang sudah tidak mungkin di masa lalu) menggunakan 'had had' + past participle.", paket: 2 },
  { id: "le38", subtes: "LBE", topic: "Reading Comprehension", q: "\"The company invested heavily in employee training, resulting in higher productivity and lower turnover.\" What was the result of the company's investment?", opts: ["Lower productivity and higher turnover", "Higher productivity and lower turnover", "No change in performance", "Increased employee turnover only"], answer: 1, pembahasan: "Kalimat menyatakan hasil investasi pelatihan adalah produktivitas lebih tinggi dan turnover karyawan lebih rendah.", paket: 2 },
  { id: "le39", subtes: "LBE", topic: "Vocabulary", q: "The term 'redundant' in a workplace context most closely means…", opts: ["Essential", "No longer needed", "Highly skilled", "Newly hired"], answer: 1, pembahasan: "'Redundant' dalam konteks pekerjaan berarti tidak lagi dibutuhkan (no longer needed).", paket: 2 },
  { id: "le40", subtes: "LBE", topic: "Grammar", q: "Choose the correct sentence:", opts: ["Each of the students have submitted their assignment.", "Each of the students has submitted their assignment.", "Each of the students submitting their assignment.", "Each of the students is submit their assignment."], answer: 1, pembahasan: "'Each' selalu diikuti kata kerja tunggal, sehingga memakai 'has submitted'.", paket: 2 },
  { id: "le41", subtes: "LBE", topic: "Reading Comprehension", q: "\"While automation increases efficiency, it also raises concerns about job displacement in certain industries.\" This sentence presents…", opts: ["Only the benefits of automation", "Only the drawbacks of automation", "Both a benefit and a concern about automation", "A history of automation"], answer: 2, pembahasan: "Kalimat menyajikan dua sisi: manfaat automasi (efisiensi) dan kekhawatirannya (pergeseran pekerjaan).", paket: 2 },
  { id: "le42", subtes: "LBE", topic: "Vocabulary", q: "The word 'meticulous' in \"a meticulous review process\" is closest in meaning to…", opts: ["Careless", "Very careful and detailed", "Quick", "Optional"], answer: 1, pembahasan: "'Meticulous' berarti sangat teliti dan detail (very careful and detailed).", paket: 2 },
  { id: "le43", subtes: "LBE", topic: "Grammar", q: "\"The report ___ by the team before it is submitted tomorrow.\" Choose the correct form:", opts: ["will review", "will be reviewed", "reviews", "is review"], answer: 1, pembahasan: "Bentuk pasif future tense: 'will be' + past participle, sehingga 'will be reviewed'.", paket: 2 },
  { id: "le44", subtes: "LBE", topic: "Reading Comprehension", q: "\"Critics argue that while the film's visuals are stunning, its storyline lacks depth.\" According to the critics, what is the film's weakness?", opts: ["Its visuals", "Its storyline", "Its length", "Its cast"], answer: 1, pembahasan: "Kritikus menyatakan visual film bagus, tetapi alur ceritanya (storyline) kurang mendalam — itu kelemahannya.", paket: 2 },
  { id: "le45", subtes: "LBE", topic: "Vocabulary", q: "The term 'sustainable growth' most closely means…", opts: ["Growth that depletes resources quickly", "Growth that can be maintained over the long term without harm", "Growth that only benefits shareholders", "Growth that happens instantly"], answer: 1, pembahasan: "'Sustainable growth' berarti pertumbuhan yang dapat dipertahankan dalam jangka panjang tanpa merusak sumber daya.", paket: 2 },
];
